--
-- Structure de la table `pages`
--

CREATE TABLE IF NOT EXISTS `pages` (
  `id` int(11) NOT NULL,
  `website_id` int(11) DEFAULT NULL,
  `template_id` int(11) DEFAULT NULL,
  `title` varchar(255) NOT NULL,
  `excerpt` text DEFAULT NULL,
  `slug` varchar(255) NOT NULL,
  `template` varchar(50) NOT NULL DEFAULT 'standard',
  `show_header` tinyint(1) DEFAULT 1,
  `show_footer` tinyint(1) DEFAULT 1,
  `show_nav` tinyint(1) DEFAULT 1,
  `content` longtext DEFAULT NULL,
  `custom_css` text DEFAULT NULL,
  `custom_js` text DEFAULT NULL,
  `builder_mode` enum('ia','sections','dnd') DEFAULT 'ia',
  `builder_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`builder_data`)),
  `file_path` varchar(255) DEFAULT NULL,
  `is_file_based` tinyint(1) DEFAULT 0,
  `meta_title` varchar(160) DEFAULT NULL,
  `meta_description` varchar(320) DEFAULT NULL,
  `header_type` varchar(50) DEFAULT 'principal',
  `footer_type` varchar(50) DEFAULT 'principal',
  `header_custom` longtext DEFAULT NULL,
  `footer_custom` longtext DEFAULT NULL,
  `h1` varchar(255) DEFAULT NULL,
  `focus_keyword` varchar(255) DEFAULT NULL,
  `ai_description` text DEFAULT NULL,
  `featured_image` varchar(500) DEFAULT NULL,
  `category` varchar(100) DEFAULT NULL,
  `tags` text DEFAULT NULL,
  `content_type` varchar(50) DEFAULT NULL,
  `page_category` enum('frontend','system','landing','blog','legal') DEFAULT 'frontend',
  `page_type` enum('public','private','system','form','utility') DEFAULT 'public',
  `status` enum('draft','published','archived') DEFAULT 'draft',
  `header_enabled` tinyint(1) DEFAULT 1,
  `footer_enabled` tinyint(1) DEFAULT 1,
  `created_at` datetime DEFAULT current_timestamp(),
  `created_by` int(11) DEFAULT NULL,
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `published_at` datetime DEFAULT NULL,
  `reading_time` int(11) DEFAULT 5,
  `seo_score` int(11) DEFAULT 0,
  `views` int(11) DEFAULT 0,
  `serp_position` int(11) DEFAULT 0,
  `visitors` int(11) DEFAULT 0,
  `template_name` varchar(50) DEFAULT 'default',
  `type` varchar(50) DEFAULT 'page',
  `layout` varchar(50) DEFAULT 'page',
  `layout_template` varchar(50) DEFAULT 'default',
  `hero_data` text DEFAULT NULL,
  `sections_data` text DEFAULT NULL,
  `sidebar_data` text DEFAULT NULL,
  `cta_data` text DEFAULT NULL,
  `quartier_data` text DEFAULT NULL,
  `breadcrumb` text DEFAULT NULL,
  `seo_title` varchar(160) DEFAULT NULL,
  `seo_description` varchar(320) DEFAULT NULL,
  `seo_keywords` varchar(255) DEFAULT NULL,
  `inline_css` text DEFAULT NULL,
  `canonical_url` varchar(500) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `settings_data` longtext DEFAULT NULL,
  `serp_keyword` varchar(255) DEFAULT NULL COMMENT 'Mot-clé principal SERP',
  `is_indexed` tinyint(1) DEFAULT 0 COMMENT '0=non indexé, 1=indexé',
  `last_seo_check` datetime DEFAULT NULL COMMENT 'Dernière vérification SEO',
  `editor_type` enum('builder','sections','html') DEFAULT 'sections' COMMENT 'Type éditeur utilisé',
  `og_image` varchar(255) DEFAULT NULL COMMENT 'Image Open Graph',
  `external_css` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`external_css`)),
  `external_js` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`external_js`)),
  `secondary_keywords` text DEFAULT NULL COMMENT 'Mots-clés secondaires JSON',
  `last_serp_check` datetime DEFAULT NULL,
  `last_index_check` datetime DEFAULT NULL,
  `index_checked_at` datetime DEFAULT NULL,
  `seo_analyzed_at` datetime DEFAULT NULL,
  `seo_issues` text DEFAULT NULL,
  `use_global_css` tinyint(1) DEFAULT 1,
  `use_global_header` tinyint(1) DEFAULT 1,
  `use_global_footer` tinyint(1) DEFAULT 1,
  `header_id` int(11) DEFAULT NULL,
  `footer_id` int(11) DEFAULT NULL,
  `meta_keywords` varchar(500) DEFAULT NULL,
  `meta_robots` varchar(50) DEFAULT 'index, follow',
  `noindex` tinyint(1) NOT NULL DEFAULT 0,
  `seo_validated` tinyint(1) NOT NULL DEFAULT 0,
  `seo_validated_at` datetime DEFAULT NULL,
  `semantic_score` int(11) DEFAULT NULL,
  `semantic_data` longtext DEFAULT NULL,
  `semantic_analyzed_at` datetime DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

