(6, 1, NULL, 'Contact – Eduardo De Sul, conseiller immobilier Bordeaux', NULL, 'contact', 'standard', 1, 1, 1, '<!-- HERO CONTACT -->\n<section class=\"hero-landing\">\n  <div class=\"hero-landing-inner\">\n\n    <p class=\"hero-landing-subtitle\">\n      Bordeaux Métropole · Conseiller immobilier indépendant eXp France\n    </p>\n\n    <h1 class=\"hero-landing-title\">\n      Contactez-moi facilement\n    </h1>\n\n    <p class=\"hero-landing-description\">\n      Une question ? Un projet immobilier à Bordeaux ?  \n      Je vous réponds rapidement et sans engagement.\n    </p>\n\n    <a href=\"#section-contact\" class=\"hero-landing-cta\">\n      Envoyer un message\n    </a>\n\n  </div>\n</section>\n\n<!-- SECTION CONTACT -->\n<section id=\"section-contact\" class=\"section-white\">\n  <div class=\"contact-container\">\n\n    <!-- FORMULAIRE -->\n    <div class=\"contact-form\">\n      <h2>Envoyer un message</h2>\n      <p class=\"form-subtitle\">\n        Tous les champs marqués d\'un * sont obligatoires.\n      </p>\n\n      <form action=\"/api/contact/send.php\" method=\"POST\" id=\"contactForm\">\n        \n        <div class=\"form-group-inline\">\n          <div class=\"form-group\">\n            <label for=\"prenom\">Prénom <span class=\"required\">*</span></label>\n            <input type=\"text\" id=\"prenom\" name=\"prenom\" placeholder=\"Jean\" required>\n          </div>\n\n          <div class=\"form-group\">\n            <label for=\"nom\">Nom <span class=\"required\">*</span></label>\n            <input type=\"text\" id=\"nom\" name=\"nom\" placeholder=\"Dupont\" required>\n          </div>\n        </div>\n\n        <div class=\"form-group\">\n          <label for=\"email\">Email <span class=\"required\">*</span></label>\n          <input type=\"email\" id=\"email\" name=\"email\" placeholder=\"jean.dupont@email.com\" required>\n        </div>\n\n        <div class=\"form-group\">\n          <label for=\"telephone\">Téléphone <span class=\"required\">*</span></label>\n          <input type=\"tel\" id=\"telephone\" name=\"telephone\" placeholder=\"06 00 00 00 00\" required>\n        </div>\n\n        <div class=\"form-group\">\n          <label for=\"sujet\">Sujet de votre demande <span class=\"required\">*</span></label>\n          <select id=\"sujet\" name=\"sujet\" required>\n            <option value=\"\">-- Sélectionner un sujet --</option>\n            <option value=\"vente\">Je veux vendre un bien</option>\n            <option value=\"achat\">Je veux acheter un bien</option>\n            <option value=\"estimation\">Je veux une estimation</option>\n            <option value=\"investissement\">Je veux investir</option>\n            <option value=\"autre\">Autre demande</option>\n          </select>\n        </div>\n\n        <div class=\"form-group\">\n          <label for=\"message\">Votre message <span class=\"required\">*</span></label>\n          <textarea id=\"message\" name=\"message\" placeholder=\"Décrivez votre projet immobilier...\" required></textarea>\n        </div>\n\n        <div class=\"form-group checkbox-group\">\n          <label style=\"display: flex; gap: 10px; align-items: flex-start; font-weight: normal;\">\n            <input type=\"checkbox\" name=\"rgpd\" required style=\"margin-top: 4px;\">\n            <span style=\"font-size: 0.9rem; color: #4a5568;\">\n              J\'accepte que mes données soient utilisées pour être recontacté.<br>\n              Voir la <a href=\"/front/pages/politique-confidentialite.php\" class=\"link-policy\">politique de confidentialité</a>.\n            </span>\n          </label>\n        </div>\n\n        <button type=\"submit\" class=\"btn-submit\">Envoyer ma demande</button>\n      </form>\n\n      <div class=\"form-success-message\" style=\"display: none;\">\n        <p>✅ Votre message a été envoyé avec succès ! Je vous recontacterai très rapidement.</p>\n      </div>\n\n    </div>\n\n    <!-- SIDEBAR -->\n    <aside class=\"contact-sidebar\">\n      \n      <div class=\"sidebar-card\">\n        <h3>Mes coordonnées</h3>\n        <ul>\n          <li>\n            <span class=\"sidebar-icon\">📍</span>\n            <div>\n              <strong>Localisation</strong>\n              <p>Bordeaux et métropole</p>\n            </div>\n          </li>\n          <li>\n            <span class=\"sidebar-icon\">📞</span>\n            <div>\n              <strong>Téléphone</strong>\n              <p><a href=\"tel:+33600000000\">06 00 00 00 00</a></p>\n            </div>\n          </li>\n          <li>\n            <span class=\"sidebar-icon\">📧</span>\n            <div>\n              <strong>Email</strong>\n              <p><a href=\"mailto:contact@eduardo-desul-immobilier.fr\">contact@eduardo-desul-immobilier.fr</a></p>\n            </div>\n          </li>\n          <li>\n            <span class=\"sidebar-icon\">⏱️</span>\n            <div>\n              <strong>Délai de réponse</strong>\n              <p>Sous 4h en semaine</p>\n            </div>\n          </li>\n        </ul>\n      </div>\n\n      <div class=\"sidebar-card\">\n        <h3>Disponibilités</h3>\n        <ul style=\"text-align: left;\">\n          <li><strong>Lun-Ven</strong><br>09:00 - 19:00</li>\n          <li><strong>Sam</strong><br>10:00 - 17:00</li>\n          <li><strong>Dim</strong><br>Sur rendez-vous</li>\n        </ul>\n      </div>\n\n      <div class=\"sidebar-card\">\n        <h3>Suivez-moi aussi</h3>\n        <div class=\"social-links\">\n          <a href=\"https://www.facebook.com/eduardodesulimmobilieriadfrance\" target=\"_blank\" class=\"social-link\">\n            <span>👍</span> Facebook\n          </a>\n          <a href=\"https://maps.app.goo.gl/1a3nKTQdK6eSLpzL6\" target=\"_blank\" class=\"social-link\">\n            <span>⭐</span> Google\n          </a>\n          <a href=\"https://www.immodvisor.com/professionnels/Mandataire-immobilier/pro/exp-france-eduardo-de-sul-76256?page=4\" target=\"_blank\" class=\"social-link\">\n            <span>📝</span> Immodvisor\n          </a>\n        </div>\n      </div>\n\n    </aside>\n\n  </div>\n</section>\n\n<!-- CTA FINALE -->\n<section class=\"cta-final\">\n  <div class=\"container max-width-900\">\n    <h2>À bientôt !</h2>\n    <p class=\"cta-description\">\n      Merci d\'avoir pensé à me contacter.<br>\n      Je suis impatient de discuter de votre projet immobilier.\n    </p>\n  </div>\n</section>', '/* ===========================\n   PAGE CONTACT\n   COULEURS : BLEU + BEIGE\n   =========================== */\n\n:root {\n  --primary: #1a4d7a;\n  --secondary: #d4a574;\n  --accent: #ff6b35;\n  --white: #ffffff;\n  --gris: #666666;\n  --gris-light: #f5f5f5;\n  --beige: #f9f6f3;\n  --shadow: 0 4px 15px rgba(0, 0, 0, 0.1);\n  --shadow-lg: 0 10px 30px rgba(0, 0, 0, 0.15);\n}\n\n* {\n  margin: 0;\n  padding: 0;\n  box-sizing: border-box;\n}\n\nhtml {\n  scroll-behavior: smooth;\n}\n\nbody {\n  font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, \'Helvetica Neue\', Arial, sans-serif;\n  font-size: 16px;\n  line-height: 1.6;\n  color: #333;\n}\n\na {\n  color: var(--primary);\n  text-decoration: none;\n  transition: all 0.3s ease;\n}\n\na:hover {\n  color: var(--secondary);\n}\n\n.container {\n  max-width: 1200px;\n  margin: 0 auto;\n  padding: 0 20px;\n}\n\n.max-width-900 {\n  max-width: 900px;\n  margin: 0 auto;\n}\n\n/* ===========================\n   HERO SECTION\n   =========================== */\n.hero-landing {\n  background: linear-gradient(135deg, var(--primary) 0%, #2d6ba3 100%);\n  color: var(--white);\n  padding: 120px 20px;\n  text-align: center;\n  min-height: 100vh;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n  overflow: hidden;\n}\n\n.hero-landing::before {\n  content: \'\';\n  position: absolute;\n  top: -50%;\n  right: -10%;\n  width: 600px;\n  height: 600px;\n  background: rgba(255, 255, 255, 0.05);\n  border-radius: 50%;\n  z-index: 0;\n}\n\n.hero-landing::after {\n  content: \'\';\n  position: absolute;\n  bottom: -30%;\n  left: -5%;\n  width: 400px;\n  height: 400px;\n  background: rgba(255, 255, 255, 0.05);\n  border-radius: 50%;\n  z-index: 0;\n}\n\n.hero-landing-inner {\n  max-width: 900px;\n  position: relative;\n  z-index: 1;\n}\n\n.hero-landing-subtitle {\n  font-size: 1rem;\n  color: rgba(255, 255, 255, 0.9);\n  margin-bottom: 20px;\n  letter-spacing: 0.5px;\n  text-transform: uppercase;\n  font-weight: 600;\n}\n\n.hero-landing-title {\n  font-size: 3.5rem;\n  font-weight: 700;\n  margin-bottom: 30px;\n  line-height: 1.2;\n  letter-spacing: -0.5px;\n}\n\n.hero-landing-description {\n  font-size: 1.3rem;\n  margin-bottom: 50px;\n  color: rgba(255, 255, 255, 0.95);\n  line-height: 1.8;\n}\n\n.hero-landing-cta {\n  display: inline-block;\n  background: var(--secondary);\n  color: var(--white);\n  padding: 16px 40px;\n  border-radius: 8px;\n  font-weight: 600;\n  font-size: 1.1rem;\n  transition: all 0.3s ease;\n  box-shadow: 0 6px 20px rgba(212, 165, 116, 0.4);\n}\n\n.hero-landing-cta:hover {\n  background: #e8b88e;\n  transform: translateY(-3px);\n  box-shadow: 0 8px 25px rgba(212, 165, 116, 0.5);\n}\n\n/* ===========================\n   CONTACT SECTION\n   =========================== */\n.section-white {\n  background: var(--white);\n  padding: 80px 20px;\n}\n\n.contact-container {\n  max-width: 1200px;\n  margin: 0 auto;\n  display: grid;\n  grid-template-columns: 1fr 380px;\n  gap: 50px;\n  align-items: start;\n}\n\n/* ===========================\n   CONTACT FORM\n   =========================== */\n.contact-form {\n  background: var(--white);\n  padding: 40px;\n  border-radius: 16px;\n  border: 2px solid #f0f0f0;\n  box-shadow: var(--shadow-lg);\n}\n\n.contact-form h2 {\n  font-size: 2rem;\n  color: var(--primary);\n  margin-bottom: 10px;\n  font-weight: 700;\n}\n\n.form-subtitle {\n  color: var(--gris);\n  font-size: 0.95rem;\n  margin-bottom: 30px;\n}\n\n.form-group {\n  margin-bottom: 25px;\n}\n\n.form-group label {\n  display: block;\n  font-weight: 600;\n  margin-bottom: 8px;\n  color: #2d3748;\n  font-size: 1rem;\n}\n\n.form-group label .required {\n  color: #e53e3e;\n  margin-left: 2px;\n}\n\n.form-group input,\n.form-group select,\n.form-group textarea {\n  width: 100%;\n  padding: 14px 16px;\n  border: 2px solid #e2e8f0;\n  border-radius: 10px;\n  font-size: 1rem;\n  transition: all 0.3s ease;\n  font-family: inherit;\n  background: var(--white);\n  color: #333;\n}\n\n.form-group input::placeholder,\n.form-group select::placeholder,\n.form-group textarea::placeholder {\n  color: #cbd5e0;\n}\n\n.form-group input:focus,\n.form-group select:focus,\n.form-group textarea:focus {\n  outline: none;\n  border-color: var(--primary);\n  box-shadow: 0 0 0 4px rgba(26, 77, 122, 0.1);\n}\n\n.form-group select {\n  cursor: pointer;\n}\n\n.form-group select option {\n  color: #333;\n  background: var(--white);\n}\n\n.form-group textarea {\n  resize: vertical;\n  min-height: 130px;\n  line-height: 1.5;\n}\n\n.form-group-inline {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 20px;\n}\n\n.checkbox-group {\n  margin: 30px 0;\n  padding: 20px;\n  background: #f7fafc;\n  border-radius: 10px;\n  border: 1px solid #e2e8f0;\n}\n\n.checkbox-group input[type=\"checkbox\"] {\n  width: auto;\n}\n\n.link-policy {\n  color: var(--primary);\n  font-weight: 600;\n  text-decoration: underline;\n}\n\n.link-policy:hover {\n  color: var(--secondary);\n}\n\n.btn-submit {\n  width: 100%;\n  padding: 16px 30px;\n  border-radius: 10px;\n  border: none;\n  background: linear-gradient(135deg, var(--primary), #2d6ba3);\n  color: var(--white);\n  font-weight: 700;\n  font-size: 1.1rem;\n  cursor: pointer;\n  transition: all 0.3s ease;\n  box-shadow: 0 6px 20px rgba(26, 77, 122, 0.3);\n  font-family: inherit;\n}\n\n.btn-submit:hover {\n  transform: translateY(-3px);\n  box-shadow: 0 8px 25px rgba(26, 77, 122, 0.4);\n}\n\n.btn-submit:active {\n  transform: translateY(-1px);\n}\n\n.form-success-message {\n  background: linear-gradient(135deg, #f0fdf4, #dcfce7);\n  border: 2px solid #22c55e;\n  color: #166534;\n  padding: 20px;\n  border-radius: 10px;\n  text-align: center;\n  font-weight: 600;\n  margin-top: 20px;\n}\n\n/* ===========================\n   SIDEBAR\n   =========================== */\n.contact-sidebar {\n  position: sticky;\n  top: 100px;\n  display: flex;\n  flex-direction: column;\n  gap: 25px;\n}\n\n.sidebar-card {\n  background: linear-gradient(135deg, #f7fafc 0%, #edf2f7 100%);\n  border-radius: 16px;\n  padding: 30px;\n  border: 2px solid #e2e8f0;\n  box-shadow: var(--shadow);\n}\n\n.sidebar-card h3 {\n  font-size: 1.3rem;\n  color: var(--primary);\n  margin-bottom: 20px;\n  font-weight: 700;\n}\n\n.sidebar-card ul {\n  list-style: none;\n  padding: 0;\n  margin: 0;\n}\n\n.sidebar-card ul li {\n  display: flex;\n  gap: 15px;\n  align-items: flex-start;\n  margin-bottom: 18px;\n  padding-bottom: 18px;\n  border-bottom: 1px solid #e2e8f0;\n}\n\n.sidebar-card ul li:last-child {\n  margin-bottom: 0;\n  padding-bottom: 0;\n  border-bottom: none;\n}\n\n.sidebar-icon {\n  font-size: 1.8rem;\n  flex-shrink: 0;\n  display: block;\n  margin-top: 2px;\n}\n\n.sidebar-card ul li strong {\n  color: var(--primary);\n  display: block;\n  font-weight: 700;\n  margin-bottom: 4px;\n}\n\n.sidebar-card ul li p {\n  color: var(--gris);\n  font-size: 0.95rem;\n  margin: 0;\n  line-height: 1.5;\n}\n\n.sidebar-card ul li a {\n  color: var(--primary);\n  font-weight: 600;\n}\n\n.sidebar-card ul li a:hover {\n  color: var(--secondary);\n  text-decoration: underline;\n}\n\n/* Social links */\n.social-links {\n  display: flex;\n  flex-direction: column;\n  gap: 12px;\n}\n\n.social-link {\n  display: flex;\n  align-items: center;\n  gap: 10px;\n  padding: 12px 16px;\n  background: var(--white);\n  border: 2px solid #e2e8f0;\n  border-radius: 8px;\n  color: var(--primary);\n  font-weight: 600;\n  transition: all 0.3s ease;\n  text-align: center;\n  justify-content: center;\n}\n\n.social-link span {\n  font-size: 1.2rem;\n}\n\n.social-link:hover {\n  border-color: var(--secondary);\n  background: linear-gradient(135deg, rgba(212, 165, 116, 0.1), rgba(26, 77, 122, 0.05));\n  color: var(--secondary);\n  transform: translateY(-2px);\n}\n\n/* ===========================\n   CALL TO ACTION\n   =========================== */\n.cta-final {\n  background: linear-gradient(135deg, var(--primary) 0%, #2d6ba3 100%);\n  color: var(--white);\n  padding: 100px 20px;\n  text-align: center;\n}\n\n.cta-final h2 {\n  font-size: 2.8rem;\n  margin-bottom: 20px;\n  font-weight: 700;\n  line-height: 1.2;\n}\n\n.cta-description {\n  font-size: 1.2rem;\n  color: rgba(255, 255, 255, 0.95);\n  line-height: 1.8;\n}\n\n/* ===========================\n   RESPONSIVE DESIGN\n   =========================== */\n@media (max-width: 1024px) {\n  .contact-container {\n    grid-template-columns: 1fr;\n    gap: 40px;\n  }\n\n  .contact-sidebar {\n    position: static;\n  }\n}\n\n@media (max-width: 768px) {\n  .hero-landing-title {\n    font-size: 2.2rem;\n  }\n\n  .hero-landing-description {\n    font-size: 1.1rem;\n    margin-bottom: 40px;\n  }\n\n  .contact-form {\n    padding: 30px;\n  }\n\n  .contact-form h2 {\n    font-size: 1.6rem;\n  }\n\n  .form-group-inline {\n    grid-template-columns: 1fr;\n    gap: 0;\n  }\n\n  .section-white {\n    padding: 60px 20px;\n  }\n\n  .cta-final h2 {\n    font-size: 2rem;\n  }\n\n  .cta-description {\n    font-size: 1rem;\n  }\n\n  .sidebar-card {\n    padding: 25px;\n  }\n\n  .sidebar-card h3 {\n    font-size: 1.1rem;\n    margin-bottom: 15px;\n  }\n}\n\n@media (max-width: 480px) {\n  .hero-landing {\n    padding: 60px 15px;\n    min-height: auto;\n  }\n\n  .hero-landing-title {\n    font-size: 1.8rem;\n    margin-bottom: 20px;\n  }\n\n  .hero-landing-subtitle {\n    font-size: 0.9rem;\n  }\n\n  .hero-landing-description {\n    font-size: 1rem;\n    margin-bottom: 30px;\n  }\n\n  .section-white {\n    padding: 50px 15px;\n  }\n\n  .contact-form {\n    padding: 20px;\n  }\n\n  .contact-form h2 {\n    font-size: 1.4rem;\n    margin-bottom: 8px;\n  }\n\n  .form-subtitle {\n    margin-bottom: 20px;\n  }\n\n  .form-group {\n    margin-bottom: 18px;\n  }\n\n  .form-group label {\n    font-size: 0.95rem;\n    margin-bottom: 6px;\n  }\n\n  .form-group input,\n  .form-group select,\n  .form-group textarea {\n    padding: 12px 14px;\n    font-size: 16px;\n  }\n\n  .form-group textarea {\n    min-height: 100px;\n  }\n\n  .checkbox-group {\n    padding: 15px;\n    margin: 20px 0;\n  }\n\n  .checkbox-group label {\n    font-size: 0.85rem;\n  }\n\n  .btn-submit {\n    padding: 14px 20px;\n    font-size: 1rem;\n  }\n\n  .contact-sidebar {\n    display: grid;\n    grid-template-columns: 1fr;\n    gap: 20px;\n  }\n\n  .sidebar-card {\n    padding: 20px;\n  }\n\n  .sidebar-card h3 {\n    font-size: 1.05rem;\n    margin-bottom: 12px;\n  }\n\n  .sidebar-card ul li {\n    margin-bottom: 12px;\n    padding-bottom: 12px;\n    gap: 10px;\n  }\n\n  .sidebar-icon {\n    font-size: 1.5rem;\n  }\n\n  .sidebar-card ul li strong {\n    font-size: 0.95rem;\n    margin-bottom: 2px;\n  }\n\n  .sidebar-card ul li p {\n    font-size: 0.9rem;\n  }\n\n  .social-link {\n    padding: 10px 12px;\n    font-size: 0.9rem;\n  }\n\n  .social-link span {\n    font-size: 1rem;\n  }\n\n  .cta-final {\n    padding: 60px 15px;\n  }\n\n  .cta-final h2 {\n    font-size: 1.5rem;\n  }\n\n  .cta-description {\n    font-size: 1rem;\n  }\n}', '', 'ia', NULL, '/front/pages/contact.php', 1, 'Contact - Eduardo De Sul Immobilier Bordeaux', 'Contactez Eduardo De Sul, conseiller immobilier indépendant à Bordeaux. Estimation gratuite, conseils personnalisés.', 'principal', 'principal', NULL, NULL, 'Contactez-moi', 'contact immobilier bordeaux', NULL, NULL, NULL, NULL, NULL, 'frontend', 'form', 'published', 1, 1, '2026-01-24 01:35:17', NULL, '2026-02-08 04:08:19', NULL, 5, 93, 0, 0, 0, 'form', 'page', 'page', 'default', '{\"title\":\"Contactez-moi\",\"subtitle\