(14, 1, NULL, 'Médiation – Eduardo De Sul Immobilier', NULL, 'mediation', 'legal', 1, 1, 1, '', NULL, NULL, 'ia', NULL, '/front/pages/mediation.php', 1, 'Médiation de la consommation - Eduardo De Sul Immobilier', 'Informations sur le médiateur de la consommation pour Eduardo De Sul, conseiller immobilier indépendant eXp France.', 'principal', 'principal', NULL, NULL, 'Médiation de la consommation', 'médiation consommation', NULL, NULL, NULL, NULL, NULL, 'legal', 'system', 'published', 1, 1, '2026-01-24 01:35:17', NULL, '2026-02-08 04:12:07', NULL, 2, 85, 0, 0, 0, 'legal', 'page', 'page', 'default', '{\"title\":\"Médiation de la consommation\",\"subtitle\":\"Conformément à l\'article L.612-1 du Code de la consommation\",\"subtitle_top\":\"\",\"image\":\"\"}', '[\r\n    {\r\n        \"id\": \"sec_med1\",\r\n        \"type\": \"text\",\r\n        \"title\": \"1. Contexte légal\",\r\n        \"content\": \"<p>Conformément à l\'article L.612-1 du Code de la consommation, tout consommateur a le droit de recourir gratuitement à un médiateur de la consommation en vue de la résolution amiable d\'un litige l\'opposant à un professionnel.<\\/p><p>Cette procédure est gratuite pour le consommateur.<\\/p>\"\r\n    },\r\n    {\r\n        \"id\": \"sec_med2\",\r\n        \"type\": \"text\",\r\n        \"title\": \"2. Médiateur compétent\",\r\n        \"bgColor\": \"#f8f9fa\",\r\n        \"content\": \"<p>Pour l\'activité immobilière exercée par <strong>Eduardo De Sul – Conseiller immobilier indépendant, agent commercial affilié à eXp France<\\/strong>, le médiateur compétent est :<\\/p><p><strong>Médiation-Service – SAS Médiation-Service<\\/strong><br>Adresse : 3, Impasse de la Roche, 29200 Brest<br>Site web : <a href=\\\"https:\\/\\/www.mediation-service.fr\\\" target=\\\"_blank\\\">www.mediation-service.fr<\\/a><br>Déposer une demande : <a href=\\\"https:\\/\\/sas.mediation-service.fr\\\" target=\\\"_blank\\\">sas.mediation-service.fr<\\/a><\\/p>\"\r\n    },\r\n    {\r\n        \"id\": \"sec_med3\",\r\n        \"type\": \"text\",\r\n        \"title\": \"3. Conditions de recevabilité\",\r\n        \"content\": \"<p>Avant toute saisine du médiateur, le consommateur doit avoir tenté de résoudre son litige directement avec le professionnel par une réclamation écrite.<\\/p><p>La demande sera recevable si :<\\/p><ul><li>le consommateur justifie avoir tenté une résolution amiable préalable<\\/li><li>la demande est introduite dans les 12 mois suivant cette réclamation<\\/li><li>le litige n\'a pas été examiné par un tribunal<\\/li><li>le litige relève du champ de la consommation (et non du B2B)<\\/li><\\/ul>\"\r\n    },\r\n    {\r\n        \"id\": \"sec_med4\",\r\n        \"type\": \"text\",\r\n        \"title\": \"4. Contact du professionnel\",\r\n        \"bgColor\": \"#f8f9fa\",\r\n        \"content\": \"<p>Pour toute réclamation préalable obligatoire :<\\/p><p><strong>Eduardo De Sul<\\/strong><br>Conseiller immobilier indépendant – Agent commercial<br>Email : contact@eduardo-desul-immobilier.fr<br>Téléphone : 06 76 59 23 67<\\/p>\"\r\n    },\r\n    {\r\n        \"id\": \"sec_med5\",\r\n        \"type\": \"text\",\r\n        \"title\": \"5. Réseau et carte professionnelle\",\r\n        \"content\": \"<p>Activité exercée sous le statut d\'agent commercial indépendant affilié au réseau :<\\/p><p><strong>eXp France – SAS eXp France<\\/strong><br>Siège social : 53 Boulevard Haussmann, 75009 Paris<br>Carte professionnelle : <strong>CPI 7501 2016 000 010 357<\\/strong><br>Transactions immobilières<\\/p>\"\r\n    }\r\n]', '{\"title\":\"\",\"phone\":\"\",\"email\":\"\"}', '{\"title\":\"\",\"text\":\"\",\"button_text\":\"\",\"button_url\":\"\",\"urgency\":\"\"}', NULL, NULL, 'Médiation Immobilière à Nice | Eduardo De Sul Immobilier', 'Service de médiation immobilière professionnel à Nice. Résolution de conflits entre propriétaires et locataires. Contact Eduardo De Sul.', 'médiation immobilière, médiation locative, conflit propriétaire locataire, médiation Nice, résolution litiges immobiliers, expert immobilier Nice, conseil immobilier', '', '', 'Service de médiation immobilière pour résoudre les conflits entre propriétaires et locataires avec Eduardo De Sul Immobilier à Nice.', NULL, NULL, 0, NULL, 'sections', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-08 03:29:29', '[\"Contenu tr\\u00e8s insuffisant\"]', 1, 1, 1, NULL, NULL, NULL, 'index, follow', 0, 0, NULL, 5, '{\"score_semantic\":5,\"score_label\":\"Insuffisant\",\"topic_detected\":\"Page de médiation immobilière vide\",\"lexical_field\":{\"covered\":[\"médiation\",\"consommation\",\"conseiller immobilier\",\"indépendant\",\"eXp France\"],\"missing_critical\":[\"médiateur de la consommation\",\"résolution de litiges\",\"réclamation\",\"conflit\",\"procédure de médiation\",\"droits du consommateur\",\"saisine du médiateur\",\"solution amiable\",\"code de la consommation\",\"gratuit\",\"impartial\",\"indépendant\",\"coordonnées du médiateur\",\"délai de traitement\",\"conditions de recevabilité\"]},\"semantic_suggestions\":{\"words_to_add\":[{\"word\":\"médiateur de la consommation\",\"importance\":\"haute\",\"context\":\"Eduardo De Sul fait appel au médiateur de la consommation pour résoudre les litiges\"},{\"word\":\"résolution de conflits\",\"importance\":\"haute\",\"context\":\"Service gratuit de résolution de conflits entre consommateurs et professionnels\"},{\"word\":\"réclamation\",\"importance\":\"haute\",\"context\":\"Déposez votre réclamation auprès du médiateur en cas de litige\"},{\"word\":\"procédure de médiation\",\"importance\":\"moyenne\",\"context\":\"La procédure de médiation est simple et accessible à tous\"},{\"word\":\"solution amiable\",\"importance\":\"moyenne\",\"context\":\"Recherche d\'une solution amiable avant tout recours judiciaire\"}],\"expressions_to_add\":[{\"expression\":\"comment saisir le médiateur de la consommation\"},{\"expression\":\"conditions de recevabilité médiation\"},{\"expression\":\"délai de traitement médiation immobilier\"},{\"expression\":\"coordonnées médiateur consommation eXp\"}],\"questions_to_answer\":[\"Comment contacter le médiateur de la consommation ?\",\"Quelles sont les conditions pour saisir le médiateur ?\",\"Quel est le délai de traitement d\'une médiation ?\",\"La médiation est-elle gratuite ?\",\"Que faire en cas de litige avec Eduardo De Sul ?\"]},\"quick_wins\":[\"Ajouter le contenu principal sur la médiation\",\"Intégrer les coordonnées complètes du médiateur\",\"Expliquer la procédure de saisine\",\"Préciser les conditions de recevabilité\",\"Mentionner la gratuité du service\"],\"overall_assessment\":\"La page est complètement vide alors qu\'elle traite d\'un sujet obligatoire pour les professionnels immobiliers. Il est urgent d\'ajouter tout le contenu informatif sur le médiateur de la consommation, ses coordonnées, la procédure et les conditions de saisine pour respecter les obligations légales et répondre aux attentes des consommateurs.\"}', '2026-02-08 04:12:07'),
