  \"type\": \"features\",\r\n        \"title\": \"📈 Tendances du marché 2025\",\r\n        \"cols\": 2,\r\n        \"items\": [\r\n            {\r\n                \"icon\": \"✔️\",\r\n                \"title\": \"Demande stable\",\r\n                \"text\": \"Dans les quartiers centraux et prisés\"\r\n            },\r\n            {\r\n                \"icon\": \"🌿\",\r\n                \"title\": \"Extérieurs privilégiés\",\r\n                \"text\": \"Les biens avec jardin ou terrasse se vendent mieux\"\r\n            },\r\n            {\r\n                \"icon\": \"🏠\",\r\n                \"title\": \"Primo-accédants de retour\",\r\n                \"text\": \"Grâce à des taux plus favorables\"\r\n            },\r\n            {\r\n                \"icon\": \"🔧\",\r\n                \"title\": \"Travaux négociés\",\r\n                \"text\": \"Les biens à rénover subissent plus de négociation\"\r\n            }\r\n        ]\r\n    },\r\n    {\r\n        \"id\": \"sec_rm4\",\r\n        \"type\": \"cards\",\r\n        \"title\": \"📍 Analyse par quartiers\",\r\n        \"bgColor\": \"#f8f9fa\",\r\n        \"cols\": 4,\r\n        \"items\": [\r\n            {\r\n                \"icon\": \"🏛️\",\r\n                \"title\": \"Chartrons\",\r\n                \"text\": \"Prix élevés, forte demande, biens rares.\"\r\n            },\r\n            {\r\n                \"icon\": \"🌿\",\r\n                \"title\": \"Caudéran\",\r\n                \"text\": \"Maisons recherchées, clientèle familiale.\"\r\n            },\r\n            {\r\n                \"icon\": \"🚉\",\r\n                \"title\": \"Saint-Jean\",\r\n                \"text\": \"Zone dynamique, attractivité en hausse.\"\r\n            },\r\n            {\r\n                \"icon\": \"🎓\",\r\n                \"title\": \"Victoire \\/ Saint-Michel\",\r\n                \"text\": \"Quartier vivant, marché porté par les étudiants.\"\r\n            }\r\n        ]\r\n    },\r\n    {\r\n        \"id