(22, 1, NULL, 'Stratégie de vente immobilière à Bordeaux – Méthode en 5 étapes', NULL, 'strategie-vente', 'page', 1, 1, 1, '', NULL, NULL, 'ia', NULL, '/front/pages/strategie-vente.php', 1, 'Stratégie de vente immobilière : ma méthode pour vendre vite et bien', 'Découvrez la stratégie de vente professionnelle d\'Eduardo De Sul pour vendre rapidement et sereinement à Bordeaux.', 'principal', 'principal', NULL, NULL, 'Ma stratégie de vente', 'stratégie vente immobilier', NULL, NULL, NULL, NULL, NULL, 'frontend', 'public', 'published', 1, 1, '2026-01-24 01:35:17', NULL, '2026-02-08 03:27:31', NULL, 6, 68, 0, 0, 0, 'page', 'page', 'page', 'default', '{\"title\":\"Ma stratégie de vente professionnelle en 5 étapes\",\"subtitle\":\"Une méthode claire, structurée et éprouvée pour vendre au meilleur prix, sans stress, avec des acheteurs vraiment engagés.\",\"subtitle_top\":\"\",\"image\":\"\",\"cta_primary\":{\"text\":\"Demander mon plan de vente\",\"url\":\"\\/estimation\"}}', '[\r\n    {\r\n        \"id\": \"sec_s1\",\r\n        \"type\": \"text\",\r\n        \"title\": \"Pourquoi une stratégie est indispensable aujourd\'hui ?\",\r\n        \"content\": \"<p>Le marché immobilier bordelais est devenu plus technique : les acheteurs comparent tout, les banques sont plus strictes, et les biens mal positionnés peuvent perdre plusieurs milliers d\'euros ou rester sur le marché trop longtemps.<\\/p><p>Pour éviter cela, j\'ai construit une méthode simple, lisible et sécurisée que j\'utilise pour chacun de mes clients.<\\/p>\"\r\n    },\r\n    {\r\n        \"id\": \"sec_s2\",\r\n        \"type\": \"steps\",\r\n        \"title\": \"Les 5 piliers de ma méthode\",\r\n        \"bgColor\": \"#faf8f5\",\r\n        \"items\": [\r\n            {\r\n                \"title\": \"1. Analyse stratégique & estimation\",\r\n                \"text\": \"Dynamique du quartier, tendances récentes, biens concurrents, votre calendrier\"\r\n            },\r\n            {\r\n                \"title\": \"2. Préparation & valorisation\",\r\n                \"text\": \"Points forts, corrections, photos professionnelles, home staging\"\r\n            },\r\n            {\r\n                \"title\": \"3. Visibilité maximale\",\r\n                \"text\": \"Annonce optimisée, portails majeurs, réseaux sociaux, emailing ciblé\"\r\n            },\r\n            {\r\n                \"title\": \"4. Qualification des acheteurs\",\r\n                \"text\": \"Capacité de financement, niveau d\'engagement, calendrier\"\r\n            },\r\n            {\r\n                \"title\": \"5. Négociation & sécurisation\",\r\n                \"text\": \"Optimisation du prix, vérification des garanties, documents sécurisés\"\r\n            }\r\n        ]\r\n    },\r\n    {\r\n        \"id\": \"sec_s3\",\r\n        \"type\": \"features\",\r\n        \"title\": \"Les résultats de cette méthode\",\r\n        \"cols\": 3,\r\n        \"items\": [\r\n            {\r\n                \"icon\": \"⏱️\",\r\n                \"title\": \"Vente plus rapide\",\r\n                \"text\": \"Moins de temps sur le marché grâce au bon positionnement\"\r\n            },\r\n            {\r\n                \"icon\": \"💰\",\r\n                \"title\": \"Meilleur prix\",\r\n                \"text\": \"Négociation minimisée grâce à la préparation\"\r\n            },\r\n            {\r\n                \"icon\": \"😌\",\r\n                \"title\": \"Sérénité totale\",\r\n                \"text\": \"Vous gardez le contrôle à chaque étape\"\r\n            }\r\n        ]\r\n    },\r\n    {\r\n        \"id\": \"sec_s4\",\r\n        \"type\": \"cta\",\r\n        \"style\": \"gradient\",\r\n        \"title\": \"Vous voulez une stratégie personnalisée ?\",\r\n        \"text\": \"Parlez-moi de votre projet. Je vous propose un plan clair, même si vous ne vendez pas maintenant.\",\r\n        \"button_text\": \"Demander mon plan de vente personnalisé\",\r\n        \"button_url\": \"\\/estimation\"\r\n    }\r