add\":[{\"word\":\"prêt immobilier\",\"importance\":\"haute\",\"context\":\"Obtenez votre prêt immobilier aux meilleures conditions\"},{\"word\":\"crédit immobilier\",\"importance\":\"haute\",\"context\":\"Simulez votre crédit immobilier en ligne gratuitement\"},{\"word\":\"capacité d\'emprunt\",\"importance\":\"haute\",\"context\":\"Calculez votre capacité d\'emprunt selon vos revenus\"},{\"word\":\"mensualités\",\"importance\":\"moyenne\",\"context\":\"Estimez vos mensualités de remboursement\"},{\"word\":\"apport personnel\",\"importance\":\"moyenne\",\"context\":\"Optimisez votre apport personnel pour réduire le coût\"},{\"word\":\"assurance emprunteur\",\"importance\":\"moyenne\",\"context\":\"Choisissez la meilleure assurance emprunteur\"}],\"expressions_to_add\":[{\"expression\":\"simulation prêt immobilier gratuite\"},{\"expression\":\"meilleur taux immobilier Bordeaux\"},{\"expression\":\"courtier en crédit immobilier\"},{\"expression\":\"financement sans apport\"},{\"expression\":\"primo accédant Bordeaux\"}],\"questions_to_answer\":[\"Quel apport pour acheter à Bordeaux ?\",\"Comment négocier son taux immobilier ?\",\"Quelles sont les aides au financement immobilier ?\",\"Combien puis-je emprunter avec mon salaire ?\"]},\"quick_wins\":[\"Ajouter un contenu substantiel sur le financement immobilier\",\"Intégrer un calculateur de capacité d\'emprunt\",\"Détailler les étapes du financement\",\"Expliquer les différents types de prêts disponibles\"],\"overall_assessment\":\"Le contenu est actuellement inexistant malgré des métadonnées prometteuses sur le financement immobilier bordelais. Il est urgent de créer un contenu riche couvrant tous les aspects du financement immobilier pour correspondre aux attentes SEO et utilisateurs.\"}', '2026-02-08 04:09:06'),
(58, 1, NULL, 'Les Chartrons - Bordeaux', NULL, 'secteurs/chartrons-bordeaux', 'secteur', 1, 1, 1, '<section class=\"hero-landing\" style=\"\n  background: linear-gradient(rgba(30, 58, 95, 0.85), rgba(20, 40, 70, 0.90)),\n              url(\'https://images.unsplash.com/photo-1582407947304-fd86f028f716?q=80&w=2000\') center/cover;\n  padding: 100px 20px;\n  position: relative;\n\">\n  <div class=\"hero-landing-inner\" style=\"max-width:1000px;margin:0 auto;text-align:center;position:relative;z-index:2;\">\n    <p style=\"font-size:1rem;color:rgba(255,255,255,0.95);margin-bottom:15px;text-transform:uppercase;letter-spacing:2px;font-weight:500;\">\n      Bordeaux · Quartier Les Chartrons\n    </p>\n\n    <h1 class=\"hero-landing-title\" style=\"font-size:2.8rem;color:white;margin-bottom:25px;line-height:1.2;font-weight:700;\">\n      Chartrons : élégance, histoire et art de vivre bordelais\n    </h1>\n\n    <p class=\"hero-landing-subtitle\" style=\"font-size:1.2rem;color:rgba(255,255,255,0.95);max-width:800px;margin:0 auto 40px;line-height:1.6;\">\n      Ancien quartier des négociants en vin, les Chartrons mêlent rues emblématiques, immeubles en pierre, \n      vie culturelle, boutiques et douceur de vivre le long des quais rénovés.\n    </p>\n\n    <div style=\"margin-top:40px;display:flex;gap:15px;justify-content:center;flex-wrap:wrap;\">\n      <a href=\"#prix-marche\" style=\"\n        background:white;\n        color:#1e3a5f;\n        padding:15px 35px;\n        border-radius:8px;\n        font-weight:600;\n        text-decoration:none;\n        transition:all 0.3s ease;\n        box-shadow:0 4px 15px rgba(0,0,0,0.2);\n      \">Voir les prix du marché</a>\n\n      <a href=\"/estimation\" style=\"\n        background:transparent;\n        color:white;\n        padding:15px 35px;\n        border:2px solid white;\n        border-radius:8px;\n        font-weight:600;\n        text-decoration:none;\n        transition:all 0.3s ease;\n      \">Estimer mon bien aux Chartrons</a>\n    </div>\n  </div>\n</section>\n\n<section style=\"padding:20px;background:#f8f8f8;font-size:0.9rem;border-bottom:1px solid #e0e0e0;\">\n  <div style=\"max-width:1200px;margin:0 auto;\">\n    <nav aria-label=\"Fil d\'ariane\">\n      <a href=\"/\" style=\"color:#1e3a5f;text-decoration:none;\">Accueil</a> › \n      <a href=\"/secteurs\" style=\"color:#1e3a5f;text-decoration:none;\">Secteurs Bordeaux</a> › \n      <strong style=\"color:#333;\">Les Chartrons</strong>\n    </nav>\n  </div>\n</section>\n\n<section style=\"padding:80px 20px;background:white;\">\n  <div style=\"max-width:1200px;margin:0 auto;\">\n    <div style=\"display:grid;grid-template-columns:2fr 1fr;gap:50px;align-items:start;\">\n      \n      <div>\n        <article style=\"margin-bottom:60px;\">\n          <h2 style=\"font-size:2.2rem;color:#1e3a5f;margin-bottom:30px;font-weight:700;\">Chartrons : un quartier emblématique de Bordeaux</h2>\n          <p style=\"font-size:1.1rem;line-height:1.8;color:#444;margin-bottom:20px;\">\n            Les Chartrons sont l\'un des quartiers les plus prestigieux de Bordeaux, connus pour leurs \n            anciennes maisons de négociants, leurs rues commerçantes, leurs antiquaires et leur ambiance chic \n            et bohème. Le secteur bénéficie d\'une attractivité exceptionnelle grâce aux quais rénovés, \n            aux commerces haut de gamme et à sa proximité avec le centre historique.\n          </p>\n          <p style=\"font-size:1.1rem;line-height:1.8;color:#444;\">\n            Entre élégance, patrimoine et dynamisme moderne, les Chartrons offrent un cadre de vie rare \n            et recherché par les Bordelais comme par les nouveaux arrivants.\n          </p>\n        </article>\n\n        <article style=\"margin-bottom:60px;\">\n          <h2 style=\"font-size:2rem;color:#1e3a5f;margin-bottom:30px;font-weight:700;\">🌟 Les atouts majeurs des Chartrons</h2>\n          <div style=\"display:grid;grid-template-columns:repeat(2, 1fr);gap:25px;\">\n            <div style=\"background:#f9f9f9;padding:25px;border-radius:12px;border-left:4px solid #1e3a5f;\">\n              <h3 style=\"font-size:1.2rem;color:#1e3a5f;margin-bottom:10px;font-weight:600;\">🏛️ Patrimoine exceptionnel</h3>\n              <p style=\"color:#666;line-height:1.6;\">Immeubles en pierre blonde, maisons bourgeoises, architecture bordelaise authentique et préservée.</p>\n            </div>\n            \n            <div style=\"background:#f9f9f9;padding:25px;border-radius:12px;border-left:4px solid #1e3a5f;\">\n              <h3 style=\"font-size:1.2rem;color:#1e3a5f;margin-bottom:10px;font-weight:600;\">🌊 Quais rénovés</h3>\n              <p style=\"color:#666;line-height:1.6;\">Promenades, restaurants, espaces verts et vue imprenable sur la Garonne.</p>\n            </div>\n\n            <div style=\"background:#f9f9f9;padding:25px;border-radius:12px;border-left:4px solid #1e3a5f;\">\n              <h3 style=\"font-size:1.2rem;color:#1e3a5f;margin-bottom:10px;font-weight:600;\">🎨 Culture & art</h3>\n              <p style=\"color:#666;line-height:1.6;\">Galeries d\'art, brocanteurs, musées et ambiance artistique unique.</p>\n            </div>\n\n            <div style=\"background:#f9f9f9;padding:25px;border-radius:12px;border-left:4px solid #1e3a5f;\">\n              <h3 style=\"font-size:1.2rem;color:#1e3a5f;margin-bottom:10px;font-weight:600;\">🛍️ Boutiques & cafés</h3>\n              <p style=\"color:#666;line-height:1.6;\">Rue Notre-Dame animée, commerces de proximité et adresses gourmandes.</p>\n            </div>\n\n            <div style=\"background:#f9f9f9;padding:25px;border-radius:12px;border-left:4px solid #1e3a5f;\">\n              <h3 style=\"font-size:1.2rem;color:#1e3a5f;margin-bottom:10px;font-weight:600;\">🚇 Excellente mobilité</h3>\n              <p style=\"color:#666;line-height:1.6;\">Lignes de tram B et C, proximité centre-ville et accès facilités.</p>\n            </div>\n\n            <div style=\"background:#f9f9f9;padding:25px;border-radius:12px;border-left:4px solid #1e3a5f;\">\n              <h3 style=\"font-size:1.2rem;color:#1e3a5f;margin-bottom:10px;font-weight:600;\">💼 Forte attractivité</h3>\n              <p style=\"color:#666;line-height:1.6;\">Quartier très recherché pour habiter et investir, valeur sûre.</p>\n            </div>\n          </div>\n        </article>\n\n        <article id=\"prix-marche\" style=\"margin-bottom:60px;\">\n          <h2 style=\"font-size:2rem;color:#1e3a5f;margin-bottom:30px;font-weight:700;\">💰 Le marché immobilier aux Chartrons</h2>\n          \n          <div style=\"background:linear-gradient(135deg,#1e3a5f,#2c5282);color:white;padding:40px;border-radius:15px;margin-bottom:30px;box-shadow:0 10px 30px rgba(30, 58, 95, 0.2);\">\n            <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:40px;\">\n              <div style=\"text-align:center;\">\n                <p style=\"font-size:0.9rem;opacity:0.9;margin-bottom:10px;text-transform:uppercase;letter-spacing:1px;\">PRIX MOYEN AU M²</p>\n                <p style=\"font-size:2.5rem;font-weight:700;margin:0;\">6 000 - 8 500 €</p>\n              </div>\n              <div style=\"text-align:center;\">\n                <p style=\"font-size:0.9rem;opacity:0.9;margin-bottom:10px;text-transform:uppercase;letter-spacing:1px;\">RENDEMENT LOCATIF</p>\n                <p style=\"font-size:2.5rem;font-weight:700;margin:0;\">3,2 - 4,8 %</p>\n              </div>\n            </div>\n          </div>\n\n          <div style=\"display:grid;grid-template-columns:repeat(3, 1fr);gap:20px;margin-bottom:30px;\">\n            <div style=\"background:#f0f7ff;padding:20px;border-radius:10px;text-align:center;\">\n              <h4 style=\"color:#1e3a5f;margin-bottom:10px;\">T2</h4>\n              <p style=\"font-size:1.3rem;font-weight:600;color:#333;\">350 - 500k€</p>\n            </div>\n            <div style=\"background:#f0f7ff;padding:20px;border-radius:10px;text-align:center;\">\n              <h4 style=\"color:#1e3a5f;margin-bottom:10px;\">T3</h4>\n              <p style=\"font-size:1.3rem;font-weight:600;color:#333;\">500 - 750k€</p>\n            </div>\n            <div style=\"background:#f0f7ff;padding:20px;border-radius:10px;text-align:center;\">\n              <h4 style=\"color:#1e3a5f;margin-bottom:10px;\">T4+</h4>\n              <p style=\"font-size:1.3rem;font-weight:600;color:#333;\">750k€ - 1,5M€</p>\n            </div>\n          </div>\n\n          <p style=\"font-size:1.1rem;line-height:1.8;color:#444;margin-bottom:20px;\">\n            Le secteur fait partie des plus premium de Bordeaux. Les biens en pierre, immeubles bourgeois \n            et appartements rénovés se vendent très rapidement, souvent au prix ou au-dessus des estimations.\n          </p>\n          <p style=\"font-size:1.1rem;line-height:1.8;color:#444;\">\n            Les Chartrons représentent une valeur sûre pour un achat patrimonial, une résidence principale ou \n            un investissement premium avec une forte demande locative constante.\n          </p>\n        </article>\n\n        <article style=\"margin-bottom:60px;\">\n          <h2 style=\"font-size:2rem;color:#1e3a5f;margin-bottom:30px;font-weight:700;\">👥 Chartrons, pour qui ?</h2>\n          \n          <div style=\"display:grid;gap:25px;\">\n            <div style=\"background:linear-gradient(to right, #f0f7ff, white);padding:30px;border-radius:12px;border-left:5px solid #1e3a5f;\">\n              <h3 style=\"font-size:1.3rem;color:#1e3a5f;margin-bottom:15px;font-weight:600;\">👨‍👩‍👧‍👦 Familles aisées</h3>\n              <p style=\"color:#444;line-height:1.6;\">Écoles réputées, sécurité, proximité du centre-ville et des espaces verts comme le Parc Rivière.</p>\n            </div>\n            \n            <div style=\"background:linear-gradient(to right, #f0f7ff, white);padding:30px;border-radius:12px;border-left:5px solid #1e3a5f;\">\n              <h3 style=\"font-size:1.3rem;color:#1e3a5f;margin-bottom:15px;font-weight:600;\">🎯 Jeunes actifs cadres</h3>\n              <p style=\"color:#444;line-height:1.6;\">Vie urbaine raffinée, commerces de qualité, quais animés et ambiance dynamique mais élégante.</p>\n            </div>\n            \n            <div style=\"background:linear-gradient(to right, #f0f7ff, white);padding:30px;border-radius:12px;border-left:5px solid #1e3a5f;\">\n              <h3 style=\"font-size:1.3rem;color:#1e3a5f;margin-bottom:15px;font-weight:600;\">💼 Investisseurs premium</h3>\n              <p style=\"color:#444;line-height:1.6;\">Biens rares et recherchés, forte demande locative, stabilité du marché et valorisation constante.</p>\n            </div>\n          </div>\n        </article>\n\n        <article style=\"margin-bottom:60px;\">\n          <h2 style=\"font-size:2rem;color:#1e3a5f;margin-bottom:30px;font-weight:700;\">📸 Découvrir les Chartrons</h2>\n          <div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:20px;\">\n            <div style=\"position:relative;border-radius:12px;overflow:hidden;box-shadow:0 5px 15px rgba(0,0,0,0.1);\">\n              <img src=\"https://images.unsplash.com/photo-1582407947304-fd86f028f716?q=80&w=400\" alt=\"Rue Notre-Dame Chartrons\" style=\"width:100%;height:200px;object-fit:cover;\">\n              <div style=\"position:absolute;bottom:10px;left:10px;color:white;font-weight:600;text-shadow:2px 2px 4px rgba(0,0,0,0.8);\">Rue Notre-Dame</div>\n            </div>\n            <div style=\"position:relative;border-radius:12px;overflow:hidden;box-shadow:0 5px 15px rgba(0,0,0,0.1);\">\n              <img src=\"https://images.unsplash.com/photo-1590736969955-71cc94901144?q=80&w=400\" alt=\"Quais des Chartrons\" style=\"width:100%;height:200px;object-fit:cover;\">', '', '', 'ia', NULL, '/front/pages/secteurs/chartrons-bordeaux.php', 1, 'Les Chartrons Bordeaux : le quartier tendance du vin et de l\'art', 'Découvrez les Chartrons, quartier emblématique de Bordeaux. Ancien