(66, 1, NULL, 'À propos – Eduardo De Sul, conseiller immobilier Bordeaux', NULL, 'a-propos', 'standard', 1, 1, 1, '\n\n<section class=\"hero-page\" data-section-name=\"Hero\">\n    <div class=\"container\">\n        <h1>À propos d\'Eduardo De Sul</h1>\n        <p class=\"subtitle\">\n            Conseiller immobilier indépendant, spécialiste du marché bordelais,\n            engagé pour une expérience de vente simple, humaine et sécurisée.\n        </p>\n    </div>\n</section>\n\n<section class=\"section\" data-section-name=\"Parcours et Mission\">\n    <div class=\"container two-columns\">\n        <div class=\"col\">\n            <h2>Mon parcours</h2>\n            <p>\n                Après plusieurs années dans des environnements exigeants, j\'ai choisi de\n                consacrer ma carrière à l\'accompagnement des propriétaires bordelais.\n            </p>\n            <p>\n                Aujourd\'hui, je suis conseiller immobilier indépendant au sein du réseau\n                <strong>eXp France</strong>, un modèle moderne qui met l\'humain et l\'expertise locale\n                au centre de la réussite.\n            </p>\n        </div>\n        <div class=\"col\">\n            <h2>Ma mission</h2>\n            <p>\n                Vous aider à vendre votre bien dans les meilleures conditions possibles :\n                le bon prix, le bon acheteur, le bon timing.\n            </p>\n            <p>Mon travail repose sur trois piliers :</p>\n            <ul>\n                <li>✔️ Une analyse rigoureuse des données du marché bordelais</li>\n                <li>✔️ Une stratégie pensée sur mesure pour votre bien</li>\n                <li>✔️ Une communication claire, honnête et transparente</li>\n            </ul>\n        </div>\n    </div>\n</section>\n\n<section class=\"section bg-beige\" data-section-name=\"Mon Approche\">\n    <div class=\"container\">\n        <h2 style=\"text-align:center;\">Mon approche</h2>\n        <div class=\"cards-3\">\n            <div class=\"card\">\n                <h3>🎯 Simplicité</h3>\n                <p>\n                    Je transforme un parcours souvent complexe en un plan clair,\n                    lisible et rassurant à chaque étape.\n                </p>\n            </div>\n            <div class=\"card\">\n                <h3>🤝 Proximité</h3>\n                <p>\n                    Relation humaine, écoute et disponibilité sont au cœur de mon accompagnement.\n                </p>\n            </div>\n            <div class=\"card\">\n                <h3>📊 Expertise locale</h3>\n                <p>\n                    Chaque quartier de Bordeaux a ses dynamiques.\n                    Je m\'appuie sur ces données pour guider vos décisions.\n                </p>\n            </div>\n        </div>\n    </div>\n</section>\n\n<section class=\"section\" data-section-name=\"CTA Contact\">\n    <div class=\"container text-center\">\n        <h2>Envie d\'échanger sur votre projet ?</h2>\n        <p class=\"subtitle\">\n            Je serais heureux de comprendre votre situation et de vous guider sans engagement.\n        </p>\n        <a href=\"/contact\" class=\"cta-btn\">Me contacter</a>\n    </div>\n</section>', '/* ========================================\n   PAGE À PROPOS - CSS COMPLET\n   ======================================== */\n\n/* Variables globales */\n:root {\n    --primary: #6366f1;\n    --primary-dark: #4f46e5;\n    --secondary: #8b5cf6;\n    --gradient: linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%);\n    --text-dark: #1e293b;\n    --text-gray: #64748b;\n    --text-light: #94a3b8;\n    --bg-light: #f8fafc;\n    --bg-beige: #faf8f5;\n    --white: #ffffff;\n    --border: #e2e8f0;\n    --shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -2px rgba(0, 0, 0, 0.1);\n    --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -4px rgba(0, 0, 0, 0.1);\n    --radius: 12px;\n    --radius-lg: 20px;\n}\n\n/* Reset de base */\n* {\n    margin: 0;\n    padding: 0;\n    box-sizing: border-box;\n}\n\nbody {\n    font-family: \'Inter\', -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, sans-serif;\n    color: var(--text-dark);\n    line-height: 1.7;\n    background: var(--white);\n}\n\n/* Container */\n.container {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 0 24px;\n}\n\n/* ========================================\n   HERO SECTION\n   ======================================== */\n.hero-page {\n    background: var(--gradient);\n    padding: 100px 0 80px;\n    text-align: center;\n    position: relative;\n    overflow: hidden;\n}\n\n.hero-page::before {\n    content: \'\';\n    position: absolute;\n    top: 0;\n    left: 0;\n    right: 0;\n    bottom: 0;\n    background: url(\"data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.05\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E\");\n    opacity: 0.5;\n}\n\n.hero-page .container {\n    position: relative;\n    z-index: 1;\n}\n\n.hero-page h1 {\n    font-size: 3rem;\n    font-weight: 700;\n    color: var(--white);\n    margin-bottom: 20px;\n    letter-spacing: -0.5px;\n}\n\n.hero-page .subtitle {\n    font-size: 1.25rem;\n    color: rgba(255, 255, 255, 0.9);\n    max-width: 700px;\n    margin: 0 auto;\n    line-height: 1.8;\n}\n\n/* ========================================\n   SECTIONS GÉNÉRALES\n   ======================================== */\n.section {\n    padding: 80px 0;\n}\n\n.section.bg-beige {\n    background: var(--bg-beige);\n}\n\n.section h2 {\n    font-size: 2rem;\n    font-weight: 700;\n    color: var(--text-dark);\n    margin-bottom: 24px;\n    position: relative;\n}\n\n.section h2::after {\n    content: \'\';\n    position: absolute;\n    bottom: -8px;\n    left: 0;\n    width: 50px;\n    height: 3px;\n    background: var(--gradient);\n    border-radius: 2px;\n}\n\n.text-center h2::after {\n    left: 50%;\n    transform: translateX(-50%);\n}\n\n.section p {\n    color: var(--text-gray);\n    font-size: 1.05rem;\n    margin-bottom: 16px;\n}\n\n.section p:last-child {\n    margin-bottom: 0;\n}\n\n/* ========================================\n   TWO COLUMNS LAYOUT\n   ======================================== */\n.two-columns {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 60px;\n    align-items: start;\n}\n\n.two-columns .col h2 {\n    margin-bottom: 20px;\n}\n\n.two-columns .col p {\n    margin-bottom: 16px;\n}\n\n.two-columns .col ul {\n    list-style: none;\n    margin-top: 20px;\n}\n\n.two-columns .col ul li {\n    padding: 12px 0;\n    color: var(--text-gray);\n    font-size: 1.05rem;\n    display: flex;\n    align-items: flex-start;\n    gap: 10px;\n    border-bottom: 1px solid var(--border);\n}\n\n.two-columns .col ul li:last-child {\n    border-bottom: none;\n}\n\n/* ========================================\n   CARDS GRID (3 colonnes)\n   ======================================== */\n.cards-3 {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 30px;\n    margin-top: 40px;\n}\n\n.card {\n    background: var(--white);\n    padding: 32px;\n    border-radius: var(--radius-lg);\n    box-shadow: var(--shadow);\n    transition: all 0.3s ease;\n    border: 1px solid var(--border);\n}\n\n.card:hover {\n    transform: translateY(-5px);\n    box-shadow: var(--shadow-lg);\n    border-color: var(--primary);\n}\n\n.card h3 {\n    font-size: 1.25rem;\n    font-weight: 600;\n    color: var(--text-dark);\n    margin-bottom: 16px;\n    display: flex;\n    align-items: center;\n    gap: 8px;\n}\n\n.card p {\n    color: var(--text-gray);\n    font-size: 1rem;\n    line-height: 1.7;\n    margin: 0;\n}\n\n/* ========================================\n   CTA SECTION\n   ======================================== */\n.text-center {\n    text-align: center;\n}\n\n.text-center h2 {\n    margin-bottom: 16px;\n}\n\n.text-center h2::after {\n    display: none;\n}\n\n.text-center .subtitle {\n    font-size: 1.15rem;\n    color: var(--text-gray);\n    max-width: 500px;\n    margin: 0 auto 32px;\n}\n\n/* Bouton CTA */\n.cta-btn {\n    display: inline-flex;\n    align-items: center;\n    justify-content: center;\n    padding: 16px 40px;\n    background: var(--gradient);\n    color: var(--white);\n    font-size: 1.05rem;\n    font-weight: 600;\n    text-decoration: none;\n    border-radius: 50px;\n    box-shadow: 0 4px 15px rgba(99, 102, 241, 0.4);\n    transition: all 0.3s ease;\n    border: none;\n    cursor: pointer;\n}\n\n.cta-btn:hover {\n    transform: translateY(-2px);\n    box-shadow: 0 6px 20px rgba(99, 102, 241, 0.5);\n}\n\n.cta-btn:active {\n    transform: translateY(0);\n}\n\n/* ========================================\n   RESPONSIVE\n   ======================================== */\n@media (max-width: 992px) {\n    .hero-page {\n        padding: 80px 0 60px;\n    }\n    \n    .hero-page h1 {\n        font-size: 2.5rem;\n    }\n    \n    .hero-page .subtitle {\n        font-size: 1.1rem;\n    }\n    \n    .section {\n        padding: 60px 0;\n    }\n    \n    .two-columns {\n        grid-template-columns: 1fr;\n        gap: 40px;\n    }\n    \n    .cards-3 {\n        grid-template-columns: repeat(2, 1fr);\n        gap: 20px;\n    }\n}\n\n@media (max-width: 768px) {\n    .hero-page {\n        padding: 60px 0 50px;\n    }\n    \n    .hero-page h1 {\n        font-size: 2rem;\n    }\n    \n    .hero-page .subtitle {\n        font-size: 1rem;\n        padding: 0 16px;\n    }\n    \n    .section {\n        padding: 50px 0;\n    }\n    \n    .section h2 {\n        font-size: 1.75rem;\n    }\n    \n    .cards-3 {\n        grid-template-columns: 1fr;\n    }\n    \n    .card {\n        padding: 24px;\n    }\n    \n    .cta-btn {\n        padding: 14px 32px;\n        font-size: 1rem;\n        width: 100%;\n        max-width: 300px;\n    }\n}\n\n@media (max-width: 480px) {\n    .container {\n        padding: 0 16px;\n    }\n    \n    .hero-page h1 {\n        font-size: 1.75rem;\n    }\n    \n    .section h2 {\n        font-size: 1.5rem;\n    }\n    \n    .two-columns .col ul li {\n        font-size: 0.95rem;\n    }\n}', '', '', NULL, NULL, 0, NULL, 'Découvrez l\'histoire, les valeurs et l\'approche professionnelle d\'Eduardo De Sul, conseiller immobilier indépendant expert du marché bordelais.', 'principal', 'principal', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'frontend', 'public', 'published', 1, 1, '2026-01-28 23:16:57', NULL, '2026-02-08 03:27:52', NULL, 5, 86, 0, 0, 0, 'default', 'page', 'page', 'default', '{\"title\":\"À propos d\'Eduardo De Sul\",\"subtitle\":\"Conseiller immobilier indépendant, spécialiste du marché bordelais, engagé pour une expérience de vente simple, humaine et sécurisée.\",\"subtitle_top\":\"\",\"image\":\"\"}', '[\r\n    {\r\n        \"id\": \"sec_a1\",\r\n        \"type\": \"text\",\r\n        \"title\": \"Mon parcours\",\r\n        \"content\": \"<p>Après plusieurs années dans des environnements exigeants, j\'ai choisi de consacrer ma carrière à l\'accompagnement des propriétaires bordelais.<\\/p><p>Aujourd\'hui, je suis conseiller immobilier indépendant au sein du réseau <strong>eXp France<\\/strong>, un modèle moderne qui met l\'humain et l\'expertise locale au centre de la réussite.<\\/p>\"\r\n    },\r\n    {\r\n        \"id\": \"sec_a2\",\r\n        \"type\": \"text\",\r\n        \"title\": \"Ma mission\",\r\n        \"content\": \"<p>Vous aider à vendre votre bien dans les meilleures conditions possibles : le bon prix, le bon acheteur, le bon timing.<\\/p><p>Mon travail repose sur trois piliers :<\\/p><ul><li>✔️ Une analyse rigoureuse des données du marché bordelais<\\/li><li>✔️ Une stratégie pensée sur mesure pour votre bien<\\/li><li>✔️ Une communication claire, honnête et transparente<\\/li><\\/ul>\"\r\n    },\r\n    {\r\n        \"id\": \"sec_a3\",\r\n        \"type\": \"features\",\r\n        \"title\": \"Mon approche\",\r\n        \"bgColor\": \"#faf8f5\",\r\n        \"cols\": 3,\r\n        \"items\": [\r\n            {\r\n                \"icon\": \"🎯\",\r\n                \"title\": \"Simplicité\",\r\n                \"text\": \"Je transforme un parcours complexe en un plan clair et rassurant.\"\r\n            },\r\n            {\r\n                \"icon\": \"🤝\",\r\n                \"title\": \"Proximité\",\r\n                \"text\": \"Relation humaine, écoute et disponibilité au cœur de mon accompagnement.\"\r\n            },\r\n            {\r\n                \"icon\": \"📊\",\r\n                \"title\": \"Expertise locale\",\r\n                \"text\": \"Chaque quartier de Bordeaux a ses dynamiques. Je m\'appuie sur ces données.\"\r\n            }\r\n        ]\r\n    },\r\n    {\r\n        \"id\": \"sec_a4\",\r\n        \"type\": \"cta\",\r\n        \"style\": \"gradient\",\r\n        \"title\": \"Envie d\'échanger sur votre projet ?\",\r\n        \"text\": \"Je serais heureux de comprendre votre situation et de vous guider sans engagement.\",\r\n        \"button_text\": \"Me contacter\",\r\n        \"button_url\": \"\\/contact\"\r\n    }\r\n]', '{\"title\":\"\",\"phone\":\"\",\"email\":\"\"}', '{\"title\":\"\",\"text\":\"\",\"button_text\":\"\",\"button_url\":\"\",\"urgency\":\"\"}', NULL, NULL, 'Eduardo De Sul - Conseiller Immobilier Bordeaux | Expert Local', 'Eduardo De Sul, conseiller immobilier indépendant à Bordeaux. Accompagnement personnalisé pour vos projets immobiliers. Contact gratuit !', 'conseiller immobilier Bordeaux, agent immobilier indépendant, vente immobilière Bordeaux, expert immobilier local, accompagnement immobilier', '', '', 'Découvrez Eduardo De Sul, conseiller immobilier indépendant spécialisé sur le marché bordelais, pour un accompagnement personnalisé.', NULL, NULL, 0, NULL, 'sections', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-08 03:27:52', '[\"Meta title: longueur non optimale\",\"Contenu: 204 mots (min recommand\\u00e9: 300)\"]', 1, 1, 1, NULL, NULL, NULL, 'index, follow', 0, 0, NULL, NULL, NULL, NULL),
(69, NULL, NULL, 'Acheter un bien', NULL, 'acheter', 'default', 1, 1, 1, '<section id=\"hero\" class=\"hero-landing\">\n  <div class=\"hero-landing-inner\">\n    <p class=\"hero-subtitle\">\n      Bordeaux · Conseiller immobilier indépendant eXp France\n    </p>\n\n    <h1 class=\"hero-landing-title\">\n      Acheter votre bien à Bordeaux sereinement, avec un conseiller qui sécurise votre acquisition de A à Z\n    </h1>\n\n    <p class=\"hero-landing-description\">\n      Vous cherchez à acheter à Bordeaux ou alentours ?\n      Je vous accompagne pour trouver le bon bien, au bon prix, et éviter les pièges de l\'achat immobilier.\n    </p>\n\n    <div class=\"hero-landing-boxes\">\n      <div class=\"landing-box\">\n        <h3>Recherche ciblée et efficace</h3>\n        <p>Accès aux meilleures opportunités du marché bordelais avant tout le monde</p>\n      </div>\n\n      <div class=\"landing-box\">\n        <h3>Négociation experte</h3>\n        <p>Je négocie pour vous le meilleur prix et les meilleures conditions</p>\n      </div>\n\n      <div class=\"landing-box\">\n        <h3>Sécurisation juridique</h3>\n        <p>Vérifications complètes pour éviter les mauvaises surprises après l\'achat</p>\n      </div>\n    </div>\n\n    <a href=\"#section-contact\" class=\"hero-landing-cta\">\n      Être accompagné dans mon achat\n    </a>\n  </div>\n</section>\n\n\n<!-- PROBLÈMES / EMPATHIE -->\n<section id=\"section-problemes\" class=\"section-white\">\n  <div class=\"container\">\n\n    <div class=\"text-center section-header\">\n      <h2 class=\"section-title\">Acheter à Bordeaux ne devrait pas être un parcours du combattant</h2>\n      <p class=\"section-subtitle\">\n        Beaucoup d\'acheteurs bordelais vivent leur recherche comme une course épuisante :\n        biens survendus, concurrence féroce, visites décevantes, dossiers refusés.\n      </p>\n    </div>\n\n    <div class=\"cards-wrapper\">\n\n      <div class=\"card\">\n        <h3>Le problème externe</h3>\n        <ul>\n          <li>Marché tendu avec peu de biens disponibles au bon prix</li>\n          <li>Concurrence forte avec des acheteurs qui surenchérissent</li>\n          <li>Vendeurs qui cachent des défauts ou gonflent les prix</li>\n        </ul>\n      </div>\n\n      <div class=\"card\">\n        <h3>Le problème interne</h3>\n        <p>\n          Derrière ces difficultés, il y a souvent la même angoisse :\n          <strong>\"Et si je fais une erreur qui me coûte des milliers d\'euros ?\"</strong><br>\n          Peur de payer trop cher, peur de passer à côté du bon bien, peur des vices cachés.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <h3>Le problème injuste</h3>\n        <p>\n          Vous avez économisé, vous êtes prêt à vous engager, vous jouez le jeu.\n          Pourtant, sans réseau et sans expertise locale, vous partez désavantagé face aux vendeurs et aux autres acheteurs.\n        </p>\n        <p><strong>C\'est précisément pour rééquilibrer la balance que je suis là.</strong></p>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n\n<!-- AUTORITÉ / PREUVES -->\n<section id=\"section-preuves\" class=\"section-beige\">\n  <div class=\"container\">\n\n    <div class=\"text-center section-header\">\n      <h2 class=\"section-title\">Un chasseur immobilier expérimenté à vos côtés</h2>\n      <p class=\"section-subtitle\">\n        Je m\'appelle <strong>Eduardo De Sul</strong> et j\'accompagne les acheteurs à Bordeaux\n        pour trouver leur bien idéal et sécuriser leur acquisition, avec l\'appui du réseau\n        <strong>eXp France</strong>.\n      </p>\n    </div>\n\n    <div class=\"cards-wrapper\">\n\n      <div class=\"card\">\n        <div class=\"card-icon\">🔍</div>\n        <h3>Accès privilégié</h3>\n        <p>\n          Réseau de conseillers et d\'agences partenaires pour accéder aux biens avant leur mise sur le marché public.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <div class=\"card-icon\">💰</div>\n        <h3>Négociation rodée</h3>\n        <p>\n          Analyse fine des prix du marché bordelais pour négocier le meilleur tarif et les meilleures conditions.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <div class=\"card-icon\">🛡️</div>\n        <h3>Sécurité maximale</h3>\n        <p>\n          Vérifications juridiques, urbanistiques et techniques pour éviter les mauvaises surprises après signature.\n        </p>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n\n<!-- MÉTHODE EN 3 ÉTAPES -->\n<section id=\"section-methodologie\" class=\"section-white\">\n  <div class=\"container\">\n\n    <div class=\"text-center section-header\">\n      <h2 class=\"section-title\">Ma méthode d\'accompagnement acheteur en 3 étapes</h2>\n      <p class=\"section-subtitle\">Je transforme une recherche frustrante en un achat réussi et sécurisé.</p>\n    </div>\n\n    <div class=\"cards-wrapper\">\n\n      <div class=\"card\">\n        <div class=\"step-number\">1</div>\n        <h3>Définition précise de votre projet</h3>\n        <p>\n          Entretien approfondi pour comprendre vos besoins, votre budget, vos critères prioritaires et votre calendrier.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <div class=\"step-number\">2</div>\n        <h3>Recherche et sélection ciblée</h3>\n        <p>\n          Je vous présente uniquement les biens correspondant vraiment à vos critères, avec analyse de marché et visite accompagnée.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <div class=\"step-number\">3</div>\n        <h3>Négociation et sécurisation</h3>\n        <p>\n          Négociation du prix, vérifications juridiques et techniques, montage du dossier jusqu\'à la signature chez le notaire.\n        </p>\n      </div>\n\n    </div>\n\n    <div class=\"text-center\" style=\"margin-top:60px;\">\n      <p class=\"methodology-result\">\n        <strong>Résultat :</strong> gain de temps, sécurité, achat réussi.\n      </p>\n      <a href=\"#section-contact\" class=\"cta-btn\">Lancer ma recherche accompagnée</a>\n    </div>\n\n  </div>\n</section>\n\n\n<!-- CTA FINALE -->\n<section id=\"section-contact\" class=\"cta-final\">\n  <div class=\"container\">\n    <h2>Prêt à trouver votre bien idéal à Bordeaux ?</h2>\n    <p class=\"cta-description\">\n      Tout commence par une conversation simple pour comprendre votre projet et vos besoins.\n      Je vous présente ensuite ma méthode et les premières opportunités.\n    </p>\n    <a href=\"/contact\" class=\"cta-btn cta-btn-large\">\n      Prendre rendez-vous gratuitement\n    </a>\n  </div>\n</section>\n\n<h2>Choisir entre appartement et maison selon vos besoins</h2>\n<p>L&#039;achat d&#039;un appartement ou d&#039;une maison représente une décision majeure qui dépend de votre style de vie et de vos priorités. Un appartement offre généralement moins d&#039;entretien et un accès facilité aux centres urbains, tandis qu&#039;une maison procure plus d&#039;espace et d&#039;intimité. Analysez vos besoins familiaux, votre budget et vos préférences pour faire le choix optimal qui correspondra à votre projet de vie sur le long terme.</p>\n\n<h2>Financement et prêt immobilier : les étapes clés</h2>\n<p>Obtenir un financement adapté constitue l&#039;étape cruciale de votre projet immobilier. Un prêt immobilier nécessite une préparation rigoureuse : constitution d&#039;un apport personnel, évaluation de votre capacité d&#039;emprunt et comparaison des offres bancaires. Les taux d&#039;intérêt, la durée du crédit et les conditions d&#039;assurance influencent directement le coût total de votre acquisition. Sollicitez plusieurs établissements pour négocier les meilleures conditions de financement.</p>\n\n<h2>L&#039;importance du choix des quartiers dans votre investissement</h2>\n<p>La sélection des quartiers détermine en grande partie la réussite de votre achat immobilier. Étudiez attentivement les infrastructures locales, les transports en commun, les écoles et les commerces de proximité. Les quartiers en développement offrent souvent un potentiel d&#039;appréciation intéressant, tandis que les zones établies garantissent une stabilité des prix. Visitez les environs à différents moments pour appréhender l&#039;ambiance et la dynamique du secteur choisi.</p>', '/* ===========================\n   VARIABLES & RESETS\n   =========================== */\n:root {\n  --primary: #1a4d7a;\n  --secondary: #d4a574;\n  --accent: #ff6b35;\n  --white: #ffffff;\n  --gris: #666666;\n  --gris-light: #f5f5f5;\n  --beige: #f9f6f3;\n  --shadow: 0 4px 15px rgba(0, 0, 0, 0.1);\n}\n\n* {\n  margin: 0;\n  padding: 0;\n  box-sizing: border-box;\n}\n\nhtml {\n  scroll-behavior: smooth;\n}\n\nbody {\n  font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, \'Helvetica Neue\', Arial, sans-serif;\n  font-size: 16px;\n  line-height: 1.6;\n  color: #333;\n}\n\na {\n  color: var(--primary);\n  text-decoration: none;\n  transition: all 0.3s ease;\n}\n\n.container {\n  max-width: 1200px;\n  margin: 0 auto;\n  padding: 0 20px;\n}\n\n/* ===========================\n   HERO SECTION\n   =========================== */\n.hero-landing {\n  background: linear-gradient(135deg, var(--primary) 0%, #2d6ba3 100%);\n  color: var(--white);\n  padding: 120px 20px;\n  text-align: center;\n  min-height: 100vh;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n  overflow: hidden;\n}\n\n.hero-landing::before {\n  content: \'\';\n  position: absolute;\n  top: -50%;\n  right: -10%;\n  width: 600px;\n  height: 600px;\n  background: rgba(255, 255, 255, 0.05);\n  border-radius: 50%;\n  z-index: 0;\n}\n\n.hero-landing::after {\n  content: \'\';\n  position: absolute;\n  bottom: -30%;\n  left: -5%;\n  width: 400px;\n  height: 400px;\n  background: rgba(255, 255, 255, 0.05);\n  border-radius: 50%;\n  z-index: 0;\n}\n\n.hero-landing-inner {\n  max-width: 900px;\n  position: relative;\n  z-index: 1;\n}\n\n.hero-subtitle {\n  font-size: 1rem;\n  color: rgba(255, 255, 255, 0.9);\n  margin-bottom: 20px;\n  letter-spacing: 0.5px;\n  text-transform: uppercase;\n  font-weight: 600;\n}\n\n.hero-landing-title {\n  font-size: 3.5rem;\n  font-weight: 700;\n  margin-bottom: 30px;\n  line-height: 1.2;\n  letter-spacing: -0.5px;\n}\n\n.hero-landing-description {\n  font-size: 1.3rem;\n  margin-bottom: 50px;\n  color: rgba(255, 255, 255, 0.95);\n  line-height: 1.8;\n}\n\n.hero-landing-boxes {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n  gap: 25px;\n  margin-bottom: 50px;\n}\n\n.landing-box {\n  background: rgba(255, 255, 255, 0.1);\n  backdrop-filter: blur(10px);\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  padding: 30px;\n  border-radius: 12px;\n  text-align: left;\n  transition: all 0.3s ease;\n}\n\n.landing-box:hover {\n  background: rgba(255, 255, 255, 0.15);\n  transform: translateY(-5px);\n}\n\n.landing-box h3 {\n  font-size: 1.3rem;\n  margin-bottom: 12px;\n  font-weight: 600;\n}\n\n.landing-box p {\n  font-size: 0.95rem;\n  line-height: 1.6;\n  opacity: 0.95;\n}\n\n.hero-landing-cta {\n  display: inline-block;\n  background: var(--secondary);\n  color: var(--white);\n  padding: 16px 40px;\n  border-radius: 8px;\n  font-weight: 600;\n  font-size: 1.1rem;\n  transition: all 0.3s ease;\n  box-shadow: 0 6px 20px rgba(212, 165, 116, 0.4);\n}\n\n.hero-landing-cta:hover {\n  background: #e8b88e;\n  transform: translateY(-3px);\n  box-shadow: 0 8px 25px rgba(212, 165, 116, 0.5);\n}\n\n/* ===========================\n   SECTION STYLES\n   =========================== */\n.section-white {\n  background: var(--white);\n  padding: 100px 20px;\n}\n\n.section-beige {\n  background: var(--beige);\n  padding: 100px 20px;\n}\n\n.section-header {\n  max-width: 800px;\n  margin: 0 auto 60px;\n}\n\n.section-title {\n  font-size: 2.5rem;\n  font-weight: 700;\n  margin-bottom: 20px;\n  color: var(--primary);\n  line-height: 1.2;\n}\n\n.section-subtitle {\n  font-size: 1.1rem;\n  color: var(--gris);\n  line-height: 1.8;\n}\n\n/* ===========================\n   CARDS LAYOUT\n   =========================== */\n.cards-wrapper {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));\n  gap: 30px;\n  margin-bottom: 40px;\n}\n\n.card {\n  background: var(--white);\n  padding: 40px 30px;\n  border-radius: 12px;\n  box-shadow: var(--shadow);\n  transition: all 0.3s ease;\n  position: relative;\n}\n\n.section-beige .card {\n  background: rgba(255, 255, 255, 0.7);\n}\n\n.card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 12px 30px rgba(0, 0, 0, 0.15);\n}\n\n.card h3 {\n  font-size: 1.5rem;\n  margin-bottom: 20px;\n  color: var(--primary);\n  font-weight: 600;\n}\n\n.card p {\n  color: var(--gris);\n  line-height: 1.8;\n  margin-bottom: 15px;\n}\n\n.card ul {\n  list-style-position: inside;\n  color: var(--gris);\n}\n\n.card ul li {\n  margin-bottom: 12px;\n  line-height: 1.6;\n}\n\n.card-icon {\n  font-size: 3rem;\n  margin-bottom: 20px;\n  display: block;\n}\n\n.step-number {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  width: 50px;\n  height: 50px;\n  background: var(--secondary);\n  color: var(--white);\n  border-radius: 50%;\n  font-size: 1.8rem;\n  font-weight: 700;\n  margin-bottom: 20px;\n}\n\n/* ===========================\n   TEXT UTILITIES\n   =========================== */\n.text-center {\n  text-align: center;\n}\n\n.methodology-result {\n  font-size: 1.2rem;\n  margin-bottom: 30px;\n  color: var(--primary);\n}\n\n/* ===========================\n   CALL TO ACTION\n   =========================== */\n.cta-final {\n  background: linear-gradient(135deg, var(--primary) 0%, #2d6ba3 100%);\n  color: var(--white);\n  padding: 100px 20px;\n  text-align: center;\n}\n\n.cta-final .container {\n  max-width: 900px;\n}\n\n.cta-final h2 {\n  font-size: 2.8rem;\n  margin-bottom: 20px;\n  font-weight: 700;\n  line-height: 1.2;\n}\n\n.cta-description {\n  font-size: 1.2rem;\n  margin-bottom: 40px;\n  color: rgba(255, 255, 255, 0.95);\n  line-height: 1.8;\n}\n\n.cta-btn {\n  display: inline-block;\n  background: var(--secondary);\n  color: var(--white);\n  padding: 14px 35px;\n  border-radius: 8px;\n  font-weight: 600;\n  font-size: 1rem;\n  transition: all 0.3s ease;\n  border: 2px solid transparent;\n  box-shadow: 0 6px 20px rgba(212, 165, 116, 0.3);\n}\n\n.cta-btn:hover {\n  background: #e8b88e;\n  transform: translateY(-3px);\n  box-shadow: 0 8px 25px rgba(212, 165, 116, 0.5);\n}\n\n.cta-btn-large {\n  padding: 18px 50px;\n  font-size: 1.2rem;\n}\n\n/* ===========================\n   RESPONSIVE DESIGN\n   =========================== */\n@media (max-width: 768px) {\n  .hero-landing-title {\n    font-size: 2.2rem;\n  }\n\n  .hero-landing-description {\n    font-size: 1.1rem;\n    margin-bottom: 40px;\n  }\n\n  .hero-landing-boxes {\n    gap: 20px;\n  }\n\n  .landing-box {\n    padding: 25px 20px;\n  }\n\n  .section-title {\n    font-size: 2rem;\n  }\n\n  .card {\n    padding: 30px 20px;\n  }\n\n  .cards-wrapper {\n    gap: 20px;\n  }\n\n  .cta-final h2 {\n    font-size: 2rem;\n  }\n\n  .cta-description {\n    font-size: 1rem;\n  }\n}\n\n@media (max-width: 480px) {\n  .hero-landing {\n    padding: 60px 15px;\n    min-height: auto;\n  }\n\n  .hero-landing-title {\n    font-size: 1.8rem;\n    margin-bottom: 20px;\n  }\n\n  .hero-subtitle {\n    font-size: 0.9rem;\n  }\n\n  .hero-landing-description {\n    font-size: 1rem;\n    margin-bottom: 30px;\n  }\n\n  .hero-landing-boxes {\n    grid-template-columns: 1fr;\n  }\n\n  .section-white,\n  .section-beige {\n    padding: 60px 15px;\n  }\n\n  .section-title {\n    font-size: 1.6rem;\n    margin-bottom: 15px;\n  }\n\n  .section-header {\n    margin-bottom: 40px;\n  }\n\n  .card {\n    padding: 20px 15px;\n  }\n\n  .cta-final {\n    padding: 60px 15px;\n  }\n\n  .cta-final h2 {\n    font-size: 1.5rem;\n  }\n\n  .cta-btn,\n  .cta-btn-large {\n    padding: 12px 25px;\n    font-size: 1rem;\n  }\n}', '', 'ia', NULL, NULL, 0, 'Acheter un bien', '', 'principal', 'principal', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'frontend', 'public', 'published', 1, 1, '2026-02-04 13:20:14', NULL, '2026-02-08 04:07:05', NULL, 5, 90, 0, 0, 0, 'default', 'page', 'page', 'default', NULL, NULL, NULL, NULL, NULL, NULL, 'Acheter un bien immobilier à Bordeaux - Conseiller eXp', 'Achetez votre bien immobilier à Bordeaux en toute sérénité. Conseiller indépendant eXp vous accompagne de A à Z. Contactez-nous !', 'acheter bien immobilier Bordeaux, conseiller immobilier Bordeaux, achat maison Bordeaux, investissement immobilier Bordeaux, eXp France Bordeaux', NULL, '', 'Achetez votre bien immobilier à Bordeaux avec un conseiller eXp indépendant. Accompagnement personnalisé pour sécuriser votre acquisition.', NULL, NULL, 0, NULL, 'sections', '', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-08 03:39:36', '[\"Titre: longueur non optimale\"]', 1, 1, 1, NULL, NULL, '', 'index, follow', 0, 0, NULL, 72, '{\"score_semantic\":72,\"score_label\":\"Bon\",\"topic_detected\":\"Services d\'accompagnement achat immobilier à Bordeaux\",\"lexical_field\":{\"covered\":[\"acheter\",\"bien immobilier\",\"Bordeaux\",\"conseiller\",\"négociation\",\"financement\",\"prêt immobilier\",\"appartement\",\"maison\",\"marché immobilier\",\"acquisition\",\"recherche\",\"prix\",\"budget\",\"notaire\",\"signature\"],\"missing_critical\":[\"vente\",\"estimation\",\"diagnostics immobiliers\",\"compromis de vente\",\"acte de vente\",\"frais de notaire\",\"hypothèque\",\"crédit\",\"banque\",\"dossier de financement\",\"taux d\'intérêt\",\"assurance emprunteur\"]},\"semantic_suggestions\":{\"words_to_add\":[{\"word\":\"vente\",\"importance\":\"haute\",\"context\":\"Dans le processus d\'achat immobilier, la négociation de vente est cruciale\"},{\"word\":\"diagnostics immobiliers\",\"importance\":\"haute\",\"context\":\"Les diagnostics immobiliers obligatoires sécurisent votre achat\"},{\"word\":\"compromis de vente\",\"importance\":\"haute\",\"context\":\"La signature du compromis de vente engage légalement les deux parties\"},{\"word\":\"frais de notaire\",\"importance\":\"moyenne\",\"context\":\"Prévoyez les frais de notaire dans votre budget d\'acquisition\"},{\"word\":\"crédit immobilier\",\"importance\":\"haute\",\"context\":\"Votre crédit immobilier doit être adapté à votre capacité de remboursement\"},{\"word\":\"assurance emprunteur\",\"importance\":\"moyenne\",\"context\":\"L\'assurance emprunteur protège votre investissement immobilier\"}],\"expressions_to_add\":[{\"expression\":\"achat immobilier neuf Bordeaux\"},{\"expression\":\"achat immobilier ancien Bordeaux\"},{\"expression\":\"investissement locatif Bordeaux\"},{\"expression\":\"première acquisition immobilière\"},{\"expression\":\"achat résidence principale\"},{\"expression\":\"achat résidence secondaire\"}],\"questions_to_answer\":[\"Quels sont les frais d\'achat immobilier à prévoir ?\",\"Comment choisir entre du neuf et de l\'ancien ?\",\"Quelle est la durée moyenne d\'une transaction immobilière ?\",\"Comment éviter les pièges lors d\'un achat immobilier ?\",\"Quand faire appel à un chasseur immobilier ?\"]},\"quick_wins\":[\"Ajouter une section sur les frais d\'acquisition\",\"Développer le vocabulaire juridique de l\'immobilier\",\"Intégrer plus de termes liés au financement\",\"Mentionner les différents types d\'achat (neuf\\/ancien, résidence principale\\/secondaire)\"],\"overall_assessment\":\"Le contenu présente un bon niveau sémantique avec un champ lexical cohérent autour de l\'achat immobilier à Bordeaux. Cependant, il manque des termes juridiques et financiers essentiels pour optimiser pleinement la couverture sémantique du sujet. L\'ajout de vocabulaire spécialisé et de questions fréquentes renforcerait significativement la pertinence SEO.\"}', '2026-02-08 04:07:05');
INSERT INTO `pages` (`id`, `website_id`, `template_id`, `title`, `excerpt`, `slug`, `template`, `show_header`, `show_footer`, `show_nav`, `content`, `custom_css`, `custom_js`, `builder_mode`, `builder_data`, `file_path`, `is_file_based`, `meta_title`, `meta_description`, `header_type`, `footer_type`, `header_custom`, `footer_custom`, `h1`, `focus_keyword`, `ai_description`, `featured_image`, `category`, `tags`, `content_type`, `page_category`, `page_type`, `status`, `header_enabled`, `footer_enabled`, `created_at`, `created_by`, `updated_at`, `published_at`, `reading_time`, `seo_score`, `views`, `serp_position`, `visitors`, `template_name`, `type`, `layout`, `layout_template`, `hero_data`, `sections_data`, `sidebar_data`, `cta_data`, `quartier_data`, `breadcrumb`, `seo_title`, `seo_description`, `seo_keywords`, `inline_css`, `canonical_url`, `description`, `settings_data`, `serp_keyword`, `is_indexed`, `last_seo_check`, `editor_type`, `og_image`, `external_css`, `external_js`, `secondary_keywords`, `last_serp_check`, `last_index_check`, `index_checked_at`, `seo_analyzed_at`, `seo_issues`, `use_global_css`, `use_global_header`, `use_global_footer`, `header_id`, `footer_id`, `meta_keywords`, `meta_robots`, `noindex`, `seo_validated`, `seo_validated_at`, `semantic_score`, `semantic_data`, `semantic_analyzed_at`) VALUES
(70, NULL, NULL, 'Vendre', NULL, 'vendre', 'default', 1, 1, 1, '<!-- HERO / PROMESSE -->\n<section id=\"hero\" class=\"hero-landing\">\n  <div class=\"hero-landing-inner\">\n    <p class=\"hero-subtitle\">\n      Bordeaux · Conseiller immobilier indépendant eXp France\n    </p>\n\n    <h1 class=\"hero-landing-title\">\n      Vendre votre bien à Bordeaux au meilleur prix, avec un expert qui maximise votre vente\n    </h1>\n\n    <p class=\"hero-landing-description\">\n      Vous envisagez de vendre à Bordeaux ou alentours ?\n      Je vous accompagne pour valoriser votre bien, attirer les bons acheteurs et conclure rapidement.\n    </p>\n\n    <div class=\"hero-landing-boxes\">\n      <div class=\"landing-box\">\n        <h3>Estimation fiable et précise</h3>\n        <p>Basée sur les données réelles du marché et l\'analyse comparative locale</p>\n      </div>\n\n      <div class=\"landing-box\">\n        <h3>Marketing immobilier expert</h3>\n        <p>Visibilité maximale pour attirer les meilleurs acheteurs</p>\n      </div>\n\n      <div class=\"landing-box\">\n        <h3>Négociation gagnante</h3>\n        <p>Je défends votre prix et accélère la vente sans compromettre la valeur</p>\n      </div>\n    </div>\n\n    <a href=\"#section-contact\" class=\"hero-landing-cta\">\n      Commencer mon projet de vente\n    </a>\n  </div>\n</section>\n\n\n<!-- PROBLÈMES / EMPATHIE -->\n<section id=\"section-problemes\" class=\"section-white\">\n  <div class=\"container\">\n\n    <div class=\"text-center section-header\">\n      <h2 class=\"section-title\">Vendre, ce n\'est pas juste « afficher » le bien</h2>\n      <p class=\"section-subtitle\">\n        La plupart des vendeurs bordelais vivent leur vente comme une aventure incertaine :\n        combien de temps ? Au quel prix ? Comment attirer de vrais acheteurs ?\n      </p>\n    </div>\n\n    <div class=\"cards-wrapper\">\n\n      <div class=\"card\">\n        <h3>Le problème visible</h3>\n        <ul>\n          <li>Beaucoup de biens en vente, peu qui se vendent rapidement</li>\n          <li>Difficulté à trouver l\'estimation juste (trop bas = perte, trop haut = pas d\'offres)</li>\n          <li>Acheteurs qui négocient à la baisse faute de visibilité</li>\n        </ul>\n      </div>\n\n      <div class=\"card\">\n        <h3>Le problème émotionnel</h3>\n        <p>\n          Derrière chaque vente immobilière, il y a une histoire, des projets, des rêves :\n          <strong>\"Je dois vendre rapidement mais sans me faire avoir sur le prix\"</strong><br>\n          Peur de ne pas trouver d\'acheteur, peur de vendre trop bas, peur de la bureaucratie.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <h3>Le problème structurel</h3>\n        <p>\n          Vous avez un bien de qualité à Bordeaux, mais sans stratégie marketing \n          et accompagnement professionnel, vous risquez de ne pas exploiter son plein potentiel.\n        </p>\n        <p><strong>C\'est exactement là où je crée la différence.</strong></p>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n\n<!-- AUTORITÉ / PREUVES -->\n<section id=\"section-preuves\" class=\"section-beige\">\n  <div class=\"container\">\n\n    <div class=\"text-center section-header\">\n      <h2 class=\"section-title\">Un expert immobilier local à votre service</h2>\n      <p class=\"section-subtitle\">\n        Je m\'appelle <strong>Eduardo De Sul</strong> et j\'aide les vendeurs bordelais \n        à maximiser la vente de leur bien avec stratégie, transparence et efficacité.\n        Fort du réseau <strong>eXp France</strong>.\n      </p>\n    </div>\n\n    <div class=\"cards-wrapper\">\n\n      <div class=\"card\">\n        <div class=\"card-icon\">🎯</div>\n        <h3>Estimation scientifique</h3>\n        <p>\n          Données DVF, comparables récents, analyse du marché bordelais pour fixer le prix optimal.\n          Ni trop haut, ni trop bas – le prix qui vend.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <div class=\"card-icon\">📣</div>\n        <h3>Marketing multi-canal</h3>\n        <p>\n          Photos professionnelles, vidéos, annonces optimisées, visibilité sur tous les portails,\n          réseaux sociaux. Votre bien n\'est pas juste visible, il est désirable.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <div class=\"card-icon\">⚡</div>\n        <h3>Vente rapide et sûre</h3>\n        <p>\n          Qualification des acheteurs, montage du dossier, vérifications légales et techniques.\n          De l\'offre à la signature, je sécurise votre transaction.\n        </p>\n      </div>\n\n    </div>\n  </div>\n</section>\n\n\n<!-- MÉTHODE EN 3 ÉTAPES -->\n<section id=\"section-methodologie\" class=\"section-white\">\n  <div class=\"container\">\n\n    <div class=\"text-center section-header\">\n      <h2 class=\"section-title\">Ma méthode de vente en 3 étapes</h2>\n      <p class=\"section-subtitle\">De la préparation à la signature chez le notaire.</p>\n    </div>\n\n    <div class=\"cards-wrapper\">\n\n      <div class=\"card\">\n        <div class=\"step-number\">1</div>\n        <h3>Étude et valorisation</h3>\n        <p>\n          Visite approfondie, estimation basée sur les données réelles, conseil sur les petits aménagements\n          qui pourraient valoriser votre bien sans gros investissement.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <div class=\"step-number\">2</div>\n        <h3>Mise en marché et promotion</h3>\n        <p>\n          Photos professionnelles, annonces sur tous les portails, mise en avant auprès de mon réseau.\n          Mise en lumière de l\'essence de votre bien pour attirer les bons acheteurs.\n        </p>\n      </div>\n\n      <div class=\"card\">\n        <div class=\"step-number\">3</div>\n        <h3>Négociation et finalisation</h3>\n        <p>\n          Accompagnement des visites, sélection des bonnes offres, négociation sereine,\n          montage du dossier jusqu\'à la signature chez le notaire.\n        </p>\n      </div>\n\n    </div>\n\n    <div class=\"text-center\" style=\"margin-top:60px;\">\n      <p class=\"methodology-result\">\n        <strong>Résultat :</strong> vente rapide, au meilleur prix, sans stress.\n      </p>\n      <a href=\"#section-contact\" class=\"cta-btn\">Préparer ma vente dès aujourd\'hui</a>\n    </div>\n\n  </div>\n</section>\n\n\n<!-- CTA FINALE -->\n<section id=\"section-contact\" class=\"cta-final\">\n  <div class=\"container\">\n    <h2>Prêt à lancer votre vente à Bordeaux ?</h2>\n    <p class=\"cta-description\">\n      Une première conversation sans engagement pour évaluer votre bien et votre projet.\n      Je vous proposerai une stratégie adaptée et un calendrier réaliste.\n    </p>\n    <a href=\"/contact\" class=\"cta-btn cta-btn-large\">\n      Demander une évaluation gratuite\n    </a>\n  </div>\n</section>', '/* ===========================\n   VARIABLES & RESETS\n   =========================== */\n:root {\n  --primary: #1a4d7a;\n  --secondary: #d4a574;\n  --accent: #ff6b35;\n  --white: #ffffff;\n  --gris: #666666;\n  --gris-light: #f5f5f5;\n  --beige: #f9f6f3;\n  --shadow: 0 4px 15px rgba(0, 0, 0, 0.1);\n}\n\n* {\n  margin: 0;\n  padding: 0;\n  box-sizing: border-box;\n}\n\nhtml {\n  scroll-behavior: smooth;\n}\n\nbody {\n  font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, \'Helvetica Neue\', Arial, sans-serif;\n  font-size: 16px;\n  line-height: 1.6;\n  color: #333;\n}\n\na {\n  color: var(--primary);\n  text-decoration: none;\n  transition: all 0.3s ease;\n}\n\n.container {\n  max-width: 1200px;\n  margin: 0 auto;\n  padding: 0 20px;\n}\n\n/* ===========================\n   HERO SECTION\n   =========================== */\n.hero-landing {\n  background: linear-gradient(135deg, var(--primary) 0%, #2d6ba3 100%);\n  color: var(--white);\n  padding: 120px 20px;\n  text-align: center;\n  min-height: 100vh;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n  overflow: hidden;\n}\n\n.hero-landing::before {\n  content: \'\';\n  position: absolute;\n  top: -50%;\n  right: -10%;\n  width: 600px;\n  height: 600px;\n  background: rgba(255, 255, 255, 0.05);\n  border-radius: 50%;\n  z-index: 0;\n}\n\n.hero-landing::after {\n  content: \'\';\n  position: absolute;\n  bottom: -30%;\n  left: -5%;\n  width: 400px;\n  height: 400px;\n  background: rgba(255, 255, 255, 0.05);\n  border-radius: 50%;\n  z-index: 0;\n}\n\n.hero-landing-inner {\n  max-width: 900px;\n  position: relative;\n  z-index: 1;\n}\n\n.hero-subtitle {\n  font-size: 1rem;\n  color: rgba(255, 255, 255, 0.9);\n  margin-bottom: 20px;\n  letter-spacing: 0.5px;\n  text-transform: uppercase;\n  font-weight: 600;\n}\n\n.hero-landing-title {\n  font-size: 3.5rem;\n  font-weight: 700;\n  margin-bottom: 30px;\n  line-height: 1.2;\n  letter-spacing: -0.5px;\n}\n\n.hero-landing-description {\n  font-size: 1.3rem;\n  margin-bottom: 50px;\n  color: rgba(255, 255, 255, 0.95);\n  line-height: 1.8;\n}\n\n.hero-landing-boxes {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n  gap: 25px;\n  margin-bottom: 50px;\n}\n\n.landing-box {\n  background: rgba(255, 255, 255, 0.1);\n  backdrop-filter: blur(10px);\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  padding: 30px;\n  border-radius: 12px;\n  text-align: left;\n  transition: all 0.3s ease;\n}\n\n.landing-box:hover {\n  background: rgba(255, 255, 255, 0.15);\n  transform: translateY(-5px);\n}\n\n.landing-box h3 {\n  font-size: 1.3rem;\n  margin-bottom: 12px;\n  font-weight: 600;\n}\n\n.landing-box p {\n  font-size: 0.95rem;\n  line-height: 1.6;\n  opacity: 0.95;\n}\n\n.hero-landing-cta {\n  display: inline-block;\n  background: var(--secondary);\n  color: var(--white);\n  padding: 16px 40px;\n  border-radius: 8px;\n  font-weight: 600;\n  font-size: 1.1rem;\n  transition: all 0.3s ease;\n  box-shadow: 0 6px 20px rgba(212, 165, 116, 0.4);\n}\n\n.hero-landing-cta:hover {\n  background: #e8b88e;\n  transform: translateY(-3px);\n  box-shadow: 0 8px 25px rgba(212, 165, 116, 0.5);\n}\n\n/* ===========================\n   SECTION STYLES\n   =========================== */\n.section-white {\n  background: var(--white);\n  padding: 100px 20px;\n}\n\n.section-beige {\n  background: var(--beige);\n  padding: 100px 20px;\n}\n\n.section-header {\n  max-width: 800px;\n  margin: 0 auto 60px;\n}\n\n.section-title {\n  font-size: 2.5rem;\n  font-weight: 700;\n  margin-bottom: 20px;\n  color: var(--primary);\n  line-height: 1.2;\n}\n\n.section-subtitle {\n  font-size: 1.1rem;\n  color: var(--gris);\n  line-height: 1.8;\n}\n\n/* ===========================\n   CARDS LAYOUT\n   =========================== */\n.cards-wrapper {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));\n  gap: 30px;\n  margin-bottom: 40px;\n}\n\n.card {\n  background: var(--white);\n  padding: 40px 30px;\n  border-radius: 12px;\n  box-shadow: var(--shadow);\n  transition: all 0.3s ease;\n  position: relative;\n}\n\n.section-beige .card {\n  background: rgba(255, 255, 255, 0.7);\n}\n\n.card:hover {\n  transform: translateY(-8px);\n  box-shadow: 0 12px 30px rgba(0, 0, 0, 0.15);\n}\n\n.card h3 {\n  font-size: 1.5rem;\n  margin-bottom: 20px;\n  color: var(--primary);\n  font-weight: 600;\n}\n\n.card p {\n  color: var(--gris);\n  line-height: 1.8;\n  margin-bottom: 15px;\n}\n\n.card ul {\n  list-style-position: inside;\n  color: var(--gris);\n}\n\n.card ul li {\n  margin-bottom: 12px;\n  line-height: 1.6;\n}\n\n.card-icon {\n  font-size: 3rem;\n  margin-bottom: 20px;\n  display: block;\n}\n\n.step-number {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  width: 50px;\n  height: 50px;\n  background: var(--secondary);\n  color: var(--white);\n  border-radius: 50%;\n  font-size: 1.8rem;\n  font-weight: 700;\n  margin-bottom: 20px;\n}\n\n/* ===========================\n   TEXT UTILITIES\n   =========================== */\n.text-center {\n  text-align: center;\n}\n\n.methodology-result {\n  font-size: 1.2rem;\n  margin-bottom: 30px;\n  color: var(--primary);\n}\n\n/* ===========================\n   CALL TO ACTION\n   =========================== */\n.cta-final {\n  background: linear-gradient(135deg, var(--primary) 0%, #2d6ba3 100%);\n  color: var(--white);\n  padding: 100px 20px;\n  text-align: center;\n}\n\n.cta-final .container {\n  max-width: 900px;\n}\n\n.cta-final h2 {\n  font-size: 2.8rem;\n  margin-bottom: 20px;\n  font-weight: 700;\n  line-height: 1.2;\n}\n\n.cta-description {\n  font-size: 1.2rem;\n  margin-bottom: 40px;\n  color: rgba(255, 255, 255, 0.95);\n  line-height: 1.8;\n}\n\n.cta-btn {\n  display: inline-block;\n  background: var(--secondary);\n  color: var(--white);\n  padding: 14px 35px;\n  border-radius: 8px;\n  font-weight: 600;\n  font-size: 1rem;\n  transition: all 0.3s ease;\n  border: 2px solid transparent;\n  box-shadow: 0 6px 20px rgba(212, 165, 116, 0.3);\n}\n\n.cta-btn:hover {\n  background: #e8b88e;\n  transform: translateY(-3px);\n  box-shadow: 0 8px 25px rgba(212, 165, 116, 0.5);\n}\n\n.cta-btn-large {\n  padding: 18px 50px;\n  font-size: 1.2rem;\n}\n\n/* ===========================\n   RESPONSIVE DESIGN\n   =========================== */\n@media (max-width: 768px) {\n  .hero-landing-title {\n    font-size: 2.2rem;\n  }\n\n  .hero-landing-description {\n    font-size: 1.1rem;\n    margin-bottom: 40px;\n  }\n\n  .hero-landing-boxes {\n    gap: 20px;\n  }\n\n  .landing-box {\n    padding: 25px 20px;\n  }\n\n  .section-title {\n    font-size: 2rem;\n  }\n\n  .card {\n    padding: 30px 20px;\n  }\n\n  .cards-wrapper {\n    gap: 20px;\n  }\n\n  .cta-final h2 {\n    font-size: 2rem;\n  }\n\n  .cta-description {\n    font-size: 1rem;\n  }\n}\n\n@media (max-width: 480px) {\n  .hero-landing {\n    padding: 60px 15px;\n    min-height: auto;\n  }\n\n  .hero-landing-title {\n    font-size: 1.8rem;\n    margin-bottom: 20px;\n  }\n\n  .hero-subtitle {\n    font-size: 0.9rem;\n  }\n\n  .hero-landing-description {\n    font-size: 1rem;\n    margin-bottom: 30px;\n  }\n\n  .hero-landing-boxes {\n    grid-template-columns: 1fr;\n  }\n\n  .section-white,\n  .section-beige {\n    padding: 60px 15px;\n  }\n\n  .section-title {\n    font-size: 1.6rem;\n    margin-bottom: 15px;\n  }\n\n  .section-header {\n    margin-bottom: 40px;\n  }\n\n  .card {\n    padding: 20px 15px;\n  }\n\n  .cta-final {\n    padding: 60px 15px;\n  }\n\n  .cta-final h2 {\n    font-size: 1.5rem;\n  }\n\n  .cta-btn,\n  .cta-btn-large {\n    padding: 12px 25px;\n    font-size: 1rem;\n  }\n}', '', 'ia', NULL, NULL, 0, 'Vendre', '', 'principal', 'principal', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'frontend', 'public', 'published', 1, 1, '2026-02-04 13:45:38', NULL, '2026-02-08 03:40:10', NULL, 5, 90, 0, 0, 0, 'default', 'page', 'page', 'default', NULL, NULL, NULL, NULL, NULL, NULL, 'Vendre votre bien immobilier à Bordeaux | Expert eXp France', 'Vendez votre maison ou appartement à Bordeaux au meilleur prix. Estimation gratuite, accompagnement personnalisé. Contactez votre expert immobilier !', 'vendre maison Bordeaux, vendre appartement Bordeaux, agent immobilier Bordeaux, estimation immobilière Bordeaux, vente immobilier Gironde, expert immobilier eXp', NULL, '', 'Vendez votre bien immobilier à Bordeaux avec un conseiller expert eXp France. Estimation précise et accompagnement personnalisé pour maximiser votre vente.', NULL, NULL, 0, NULL, 'sections', '', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-08 03:40:10', '[\"Titre: longueur non optimale\"]', 1, 1, 1, NULL, NULL, '', 'index, follow', 0, 0, NULL, NULL, NULL, NULL),
(71, NULL, NULL, 'Secteurs', NULL, 'secteurs', 'default', 1, 1, 1, '<!-- HERO SECTION -->\n<section class=\"hero-landing\">\n  <div class=\"hero-landing-inner\">\n\n    <p class=\"hero-landing-subtitle\">\n      Bordeaux Métropole · Découvrez nos quartiers\n    </p>\n\n    <h1 class=\"hero-landing-title\">\n      Bordeaux, une ville où il fait bon vivre… et investir\n    </h1>\n\n    <p class=\"hero-landing-description\">\n      Qualité de vie, dynamisme économique, architecture exceptionnelle et quartiers aux identités fortes.\n      Découvrez ce qui fait de Bordeaux l\'un des marchés immobiliers les plus attractifs de France.\n    </p>\n\n    <div class=\"hero-landing-boxes\">\n      <div class=\"landing-box\">\n        <h3>🌟 4e ville la plus attractive</h3>\n        <p>Selon baromètres nationaux 2024–2025</p>\n      </div>\n\n      <div class=\"landing-box\">\n        <h3>💰 Prix: 4 000 à 6 500 €/m²</h3>\n        <p>Selon les quartiers et typologies</p>\n      </div>\n    </div>\n\n    <a href=\"#section-quartiers\" class=\"hero-landing-cta\">\n      Explorer les quartiers\n    </a>\n\n  </div>\n</section>\n\n<!-- HISTOIRE & CADRE DE VIE -->\n<section class=\"section-white\">\n  <div class=\"container max-width-900\">\n\n    <h2 class=\"section-title\" style=\"text-align: center;\">\n      Une ville classée, vivante et rayonnante\n    </h2>\n\n    <p class=\"text-content\">\n      Réputée pour son architecture en pierre blonde, son centre historique classé UNESCO,\n      ses quais rénovés et son ambiance chaleureuse, Bordeaux attire chaque année \n      des milliers de familles, d\'étudiants, de cadres parisiens et d\'investisseurs.\n    </p>\n\n    <p class=\"text-content\">\n      Son équilibre entre modernité (Bastide, Bassins à flot, Euratlantique)\n      et charme historique (Chartrons, Saint-Pierre, Caudéran) en fait un marché\n      unique en France, où chaque quartier raconte une histoire.\n    </p>\n\n    <div class=\"highlight-box\">\n      <h3>🌟 4e ville la plus attractive de France</h3>\n      <p>Selon plusieurs baromètres nationaux en 2024–2025.</p>\n    </div>\n\n  </div>\n</section>\n\n<!-- MARCHÉ IMMOBILIER -->\n<section class=\"section-beige\">\n  <div class=\"container max-width-900\">\n\n    <h2 class=\"section-title\" style=\"text-align: center;\">\n      Le marché immobilier bordelais en 2025\n    </h2>\n\n    <p class=\"text-content\">\n      Après une forte hausse entre 2015 et 2020, le marché bordelais s\'est stabilisé, offrant \n      aujourd\'hui des opportunités intéressantes tant pour les acheteurs que pour les investisseurs.\n    </p>\n\n    <div class=\"market-stats\">\n      <div class=\"stat-item\">\n        <div class=\"stat-label\">Prix moyens</div>\n        <div class=\"stat-value\">4 000 - 6 500 €/m²</div>\n        <div class=\"stat-desc\">selon les quartiers</div>\n      </div>\n\n      <div class=\"stat-item\">\n        <div class=\"stat-label\">Demande locative</div>\n        <div class=\"stat-value\">Extrêmement forte</div>\n        <div class=\"stat-desc\">étudiants + cadres + jeunes actifs</div>\n      </div>\n\n      <div class=\"stat-item\">\n        <div class=\"stat-label\">Rentabilité investissement</div>\n        <div class=\"stat-value\">3,5 % à 7 %</div>\n        <div class=\"stat-desc\">selon la typologie</div>\n      </div>\n\n      <div class=\"stat-item\">\n        <div class=\"stat-label\">Tendance 2025</div>\n        <div class=\"stat-value\">Marché raisonnable</div>\n        <div class=\"stat-desc\">propice aux négociations</div>\n      </div>\n    </div>\n\n    <p class=\"text-content\" style=\"margin-top: 30px;\">\n      Bordeaux reste l\'un des marchés les plus dynamiques du Sud-Ouest \n      grâce à sa qualité de vie, son bassin d\'emploi et ses infrastructures.\n    </p>\n\n    <div style=\"text-align: center; margin-top: 30px;\">\n      <a href=\"/front/pages/estimation.php\" class=\"cta-btn\">\n        Obtenir une estimation précise de mon bien\n      </a>\n    </div>\n\n  </div>\n</section>\n\n<!-- LES QUARTIERS -->\n<section id=\"section-quartiers\" class=\"section-white\">\n  <div class=\"container\">\n\n    <h2 class=\"section-title\" style=\"text-align: center; margin-bottom: 20px;\">\n      Les grands quartiers de Bordeaux\n    </h2>\n\n    <p class=\"section-intro\" style=\"max-width: 800px; margin: 0 auto 50px;\">\n      Chacun possède son ambiance, son style architectural et son profil d\'acheteurs ou de locataires.\n      Voici un aperçu des zones les plus emblématiques.\n    </p>\n\n    <div class=\"grid-quartiers\">\n\n      <div class=\"card-quartier\">\n        <div class=\"card-quartier-icon\">🏛️</div>\n        <h3>Chartrons</h3>\n        <p>Quartier prisé, ambiance village, idéal pour cadres et investisseurs patrimoniaux.</p>\n        <a href=\"/secteurs/chartrons-bordeaux\" class=\"card-quartier-link\">\n          Découvrir →\n        </a>\n      </div>\n\n      <div class=\"card-quartier\">\n        <div class=\"card-quartier-icon\">🌟</div>\n        <h3>Saint-Pierre</h3>\n        <p>Le cœur historique : ruelles, restaurants, vie culturelle, forte demande locative.</p>\n        <a href=\"/secteurs/saint-pierre-bordeaux\" class=\"card-quartier-link\">\n          Découvrir →\n        </a>\n      </div>\n\n      <div class=\"card-quartier\">\n        <div class=\"card-quartier-icon\">👨‍👩‍👧‍👦</div>\n        <h3>Caudéran</h3>\n        <p>Maisons familiales, écoles réputées, secteur idéal pour les familles.</p>\n        <a href=\"/secteurs/cauderan-bordeaux\" class=\"card-quartier-link\">\n          Découvrir →\n        </a>\n      </div>\n\n      <div class=\"card-quartier\">\n        <div class=\"card-quartier-icon\">🚀</div>\n        <h3>Bastide / Rive droite</h3>\n        <p>Quartiers en pleine transformation : excellent potentiel de valorisation.</p>\n        <a href=\"/secteurs/bastide-bordeaux\" class=\"card-quartier-link\">\n          Découvrir →\n        </a>\n      </div>\n\n      <div class=\"card-quartier\">\n        <div class=\"card-quartier-icon\">🏗️</div>\n        <h3>Bassins à flot</h3>\n        <p>Architecture moderne, attractivité jeunes actifs, forte évolution.</p>\n        <a href=\"/secteurs/bassins-a-flot-bordeaux\" class=\"card-quartier-link\">\n          Découvrir →\n        </a>\n      </div>\n\n      <div class=\"card-quartier\">\n        <div class=\"card-quartier-icon\">🏥</div>\n        <h3>Saint-Augustin</h3>\n        <p>Parfait pour les professions médicales et les étudiants du CHU.</p>\n        <a href=\"/secteurs/saint-augustin-bordeaux\" class=\"card-quartier-link\">\n          Découvrir →\n        </a>\n      </div>\n\n    </div>\n\n  </div>\n</section>\n\n<!-- QUALITÉ DE VIE -->\n<section class=\"section-beige\">\n  <div class=\"container max-width-900\">\n\n    <h2 class=\"section-title\" style=\"text-align: center;\">\n      Une qualité de vie incomparable\n    </h2>\n\n    <p class=\"text-content\">\n      Bordeaux séduit par son équilibre rare, qui crée une demande régulière, \n      que ce soit pour acheter, louer ou investir.\n    </p>\n\n    <div class=\"quality-of-life\">\n      <div class=\"qol-item\">\n        <span class=\"qol-icon\">🌿</span>\n        <div>\n          <h4>Espaces verts et pistes cyclables</h4>\n          <p>Une ville pensée pour la mobilité douce et le bien-être</p>\n        </div>\n      </div>\n\n      <div class=\"qol-item\">\n        <span class=\"qol-icon\">🚄</span>\n        <div>\n          <h4>Paris à 2h</h4>\n          <p>Attractivité pour les cadres en télétravail flexible</p>\n        </div>\n      </div>\n\n      <div class=\"qol-item\">\n        <span class=\"qol-icon\">🌊</span>\n        <div>\n          <h4>Proximité bassin d\'Arcachon & océan</h4>\n          <p>À seulement 45 minutes des plages</p>\n        </div>\n      </div>\n\n      <div class=\"qol-item\">\n        <span class=\"qol-icon\">🎓</span>\n        <div>\n          <h4>Forte communauté étudiante</h4>\n          <p>Plus de 60 000 étudiants dynamisent la ville</p>\n        </div>\n      </div>\n\n      <div class=\"qol-item\">\n        <span class=\"qol-icon\">🍷</span>\n        <div>\n          <h4>Culture et gastronomie</h4>\n          <p>Mondialement reconnus, patrimoine culinaire unique</p>\n        </div>\n      </div>\n\n      <div class=\"qol-item\">\n        <span class=\"qol-icon\">🎭</span>\n        <div>\n          <h4>Vie culturelle & événements</h4>\n          <p>Festivals, expositions, spectacles toute l\'année</p>\n        </div>\n      </div>\n    </div>\n\n  </div>\n</section>\n\n<!-- CTA FINALE -->\n<section class=\"cta-final\">\n  <div class=\"container max-width-900\">\n    <h2>Votre projet à Bordeaux commence ici</h2>\n    <p class=\"cta-description\">\n      Une simple conversation peut transformer votre vision du marché.\n    </p>\n    <a href=\"/front/pages/estimation.php\" class=\"cta-btn cta-btn-large\">\n      Discuter de votre projet\n    </a>\n  </div>\n</section>', '/* ===========================\n   PAGE SECTEURS / QUARTIERS\n   COULEURS : BLEU + BEIGE\n   =========================== */\n\n:root {\n  --primary: #1a4d7a;\n  --secondary: #d4a574;\n  --accent: #ff6b35;\n  --white: #ffffff;\n  --gris: #666666;\n  --gris-light: #f5f5f5;\n  --beige: #f9f6f3;\n  --shadow: 0 4px 15px rgba(0, 0, 0, 0.1);\n  --shadow-lg: 0 10px 30px rgba(0, 0, 0, 0.15);\n}\n\n* {\n  margin: 0;\n  padding: 0;\n  box-sizing: border-box;\n}\n\nhtml {\n  scroll-behavior: smooth;\n}\n\nbody {\n  font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, \'Helvetica Neue\', Arial, sans-serif;\n  font-size: 16px;\n  line-height: 1.6;\n  color: #333;\n}\n\na {\n  color: var(--primary);\n  text-decoration: none;\n  transition: all 0.3s ease;\n}\n\n.container {\n  max-width: 1200px;\n  margin: 0 auto;\n  padding: 0 20px;\n}\n\n.max-width-900 {\n  max-width: 900px;\n  margin: 0 auto;\n}\n\n/* ===========================\n   HERO SECTION\n   =========================== */\n.hero-landing {\n  background: linear-gradient(135deg, var(--primary) 0%, #2d6ba3 100%);\n  color: var(--white);\n  padding: 120px 20px;\n  text-align: center;\n  min-height: 100vh;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  position: relative;\n  overflow: hidden;\n}\n\n.hero-landing::before {\n  content: \'\';\n  position: absolute;\n  top: -50%;\n  right: -10%;\n  width: 600px;\n  height: 600px;\n  background: rgba(255, 255, 255, 0.05);\n  border-radius: 50%;\n  z-index: 0;\n}\n\n.hero-landing::after {\n  content: \'\';\n  position: absolute;\n  bottom: -30%;\n  left: -5%;\n  width: 400px;\n  height: 400px;\n  background: rgba(255, 255, 255, 0.05);\n  border-radius: 50%;\n  z-index: 0;\n}\n\n.hero-landing-inner {\n  max-width: 900px;\n  position: relative;\n  z-index: 1;\n}\n\n.hero-landing-subtitle {\n  font-size: 1rem;\n  color: rgba(255, 255, 255, 0.9);\n  margin-bottom: 20px;\n  letter-spacing: 0.5px;\n  text-transform: uppercase;\n  font-weight: 600;\n}\n\n.hero-landing-title {\n  font-size: 3.5rem;\n  font-weight: 700;\n  margin-bottom: 30px;\n  line-height: 1.2;\n  letter-spacing: -0.5px;\n}\n\n.hero-landing-description {\n  font-size: 1.3rem;\n  margin-bottom: 50px;\n  color: rgba(255, 255, 255, 0.95);\n  line-height: 1.8;\n}\n\n.hero-landing-boxes {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n  gap: 25px;\n  margin-bottom: 50px;\n}\n\n.landing-box {\n  background: rgba(255, 255, 255, 0.1);\n  backdrop-filter: blur(10px);\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  padding: 30px;\n  border-radius: 12px;\n  text-align: left;\n  transition: all 0.3s ease;\n}\n\n.landing-box:hover {\n  background: rgba(255, 255, 255, 0.15);\n  transform: translateY(-5px);\n}\n\n.landing-box h3 {\n  font-size: 1.3rem;\n  margin-bottom: 12px;\n  font-weight: 600;\n}\n\n.landing-box p {\n  font-size: 0.95rem;\n  line-height: 1.6;\n  opacity: 0.95;\n}\n\n.hero-landing-cta {\n  display: inline-block;\n  background: var(--secondary);\n  color: var(--white);\n  padding: 16px 40px;\n  border-radius: 8px;\n  font-weight: 600;\n  font-size: 1.1rem;\n  transition: all 0.3s ease;\n  box-shadow: 0 6px 20px rgba(212, 165, 116, 0.4);\n}\n\n.hero-landing-cta:hover {\n  background: #e8b88e;\n  transform: translateY(-3px);\n  box-shadow: 0 8px 25px rgba(212, 165, 116, 0.5);\n}\n\n/* ===========================\n   SECTION STYLES\n   =========================== */\n.section-white {\n  background: var(--white);\n  padding: 100px 20px;\n}\n\n.section-beige {\n  background: var(--beige);\n  padding: 100px 20px;\n}\n\n.section-title {\n  font-size: 2.5rem;\n  font-weight: 700;\n  margin-bottom: 20px;\n  color: var(--primary);\n  line-height: 1.2;\n}\n\n.section-intro {\n  font-size: 1.15rem;\n  color: var(--gris);\n  line-height: 1.8;\n}\n\n.text-content {\n  font-size: 1.05rem;\n  color: var(--gris);\n  line-height: 1.9;\n  margin-bottom: 25px;\n}\n\n/* ===========================\n   HIGHLIGHT BOX\n   =========================== */\n.highlight-box {\n  padding: 30px;\n  border-left: 5px solid var(--secondary);\n  background: linear-gradient(135deg, rgba(212, 165, 116, 0.05), rgba(26, 77, 122, 0.05));\n  margin: 40px 0;\n  border-radius: 8px;\n  border-right: 1px solid #e2e8f0;\n}\n\n.highlight-box h3 {\n  font-size: 1.3rem;\n  color: var(--primary);\n  margin-bottom: 8px;\n  font-weight: 700;\n}\n\n.highlight-box p {\n  margin: 0;\n  color: var(--gris);\n  font-size: 1rem;\n}\n\n/* ===========================\n   MARKET STATISTICS\n   =========================== */\n.market-stats {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));\n  gap: 25px;\n  margin: 40px 0;\n}\n\n.stat-item {\n  background: var(--white);\n  padding: 30px;\n  border-radius: 12px;\n  text-align: center;\n  box-shadow: var(--shadow);\n  transition: all 0.3s ease;\n  border: 2px solid transparent;\n}\n\n.stat-item:hover {\n  border-color: var(--secondary);\n  transform: translateY(-5px);\n  box-shadow: var(--shadow-lg);\n}\n\n.stat-label {\n  font-size: 0.85rem;\n  color: var(--gris);\n  text-transform: uppercase;\n  letter-spacing: 0.5px;\n  margin-bottom: 8px;\n  font-weight: 600;\n}\n\n.stat-value {\n  font-size: 1.8rem;\n  color: var(--primary);\n  font-weight: 700;\n  margin-bottom: 8px;\n}\n\n.stat-desc {\n  font-size: 0.9rem;\n  color: #999;\n}\n\n/* ===========================\n   QUARTIERS GRID\n   =========================== */\n.grid-quartiers {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));\n  gap: 30px;\n  margin-bottom: 40px;\n}\n\n.card-quartier {\n  background: var(--white);\n  padding: 35px 30px;\n  border-radius: 12px;\n  box-shadow: var(--shadow);\n  transition: all 0.3s ease;\n  text-align: center;\n  border: 2px solid transparent;\n  position: relative;\n}\n\n.card-quartier:hover {\n  transform: translateY(-8px);\n  box-shadow: var(--shadow-lg);\n  border-color: var(--secondary);\n}\n\n.card-quartier-icon {\n  font-size: 2.5rem;\n  margin-bottom: 15px;\n  display: block;\n}\n\n.card-quartier h3 {\n  font-size: 1.5rem;\n  color: var(--primary);\n  margin-bottom: 15px;\n  font-weight: 700;\n}\n\n.card-quartier p {\n  color: var(--gris);\n  line-height: 1.6;\n  margin-bottom: 20px;\n  font-size: 0.95rem;\n}\n\n.card-quartier-link {\n  display: inline-block;\n  color: var(--primary);\n  font-weight: 600;\n  transition: all 0.3s ease;\n  border-bottom: 2px solid transparent;\n  padding-bottom: 2px;\n}\n\n.card-quartier-link:hover {\n  color: var(--secondary);\n  border-bottom-color: var(--secondary);\n}\n\n/* ===========================\n   QUALITY OF LIFE\n   =========================== */\n.quality-of-life {\n  display: grid;\n  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));\n  gap: 35px;\n  margin: 50px 0;\n}\n\n.qol-item {\n  display: flex;\n  gap: 20px;\n  align-items: flex-start;\n}\n\n.qol-icon {\n  font-size: 2.5rem;\n  flex-shrink: 0;\n  display: block;\n  margin-top: 5px;\n}\n\n.qol-item h4 {\n  font-size: 1.2rem;\n  color: var(--primary);\n  margin-bottom: 8px;\n  font-weight: 700;\n}\n\n.qol-item p {\n  color: var(--gris);\n  font-size: 0.95rem;\n  line-height: 1.6;\n}\n\n/* ===========================\n   CALL TO ACTION\n   =========================== */\n.cta-final {\n  background: linear-gradient(135deg, var(--primary) 0%, #2d6ba3 100%);\n  color: var(--white);\n  padding: 100px 20px;\n  text-align: center;\n}\n\n.cta-final h2 {\n  font-size: 2.8rem;\n  margin-bottom: 20px;\n  font-weight: 700;\n  line-height: 1.2;\n}\n\n.cta-description {\n  font-size: 1.2rem;\n  margin-bottom: 40px;\n  color: rgba(255, 255, 255, 0.95);\n  line-height: 1.8;\n}\n\n.cta-btn {\n  display: inline-block;\n  background: var(--secondary);\n  color: var(--white);\n  padding: 14px 35px;\n  border-radius: 8px;\n  font-weight: 600;\n  font-size: 1rem;\n  transition: all 0.3s ease;\n  border: 2px solid transparent;\n  box-shadow: 0 6px 20px rgba(212, 165, 116, 0.3);\n}\n\n.cta-btn:hover {\n  background: #e8b88e;\n  transform: translateY(-3px);\n  box-shadow: 0 8px 25px rgba(212, 165, 116, 0.5);\n}\n\n.cta-btn-large {\n  padding: 18px 50px;\n  font-size: 1.2rem;\n}\n\n/* ===========================\n   RESPONSIVE DESIGN\n   =========================== */\n@media (max-width: 768px) {\n  .hero-landing-title {\n    font-size: 2.2rem;\n  }\n\n  .hero-landing-description {\n    font-size: 1.1rem;\n    margin-bottom: 40px;\n  }\n\n  .hero-landing-boxes {\n    gap: 20px;\n  }\n\n  .landing-box {\n    padding: 25px 20px;\n  }\n\n  .section-title {\n    font-size: 2rem;\n  }\n\n  .grid-quartiers {\n    gap: 20px;\n  }\n\n  .card-quartier {\n    padding: 25px 20px;\n  }\n\n  .cta-final h2 {\n    font-size: 2rem;\n  }\n\n  .cta-description {\n    font-size: 1rem;\n  }\n\n  .section-white,\n  .section-beige {\n    padding: 60px 20px;\n  }\n\n  .quality-of-life {\n    gap: 25px;\n  }\n\n  .qol-item {\n    gap: 15px;\n  }\n\n  .qol-icon {\n    font-size: 2rem;\n  }\n}\n\n@media (max-width: 480px) {\n  .hero-landing {\n    padding: 60px 15px;\n    min-height: auto;\n  }\n\n  .hero-landing-title {\n    font-size: 1.8rem;\n    margin-bottom: 20px;\n  }\n\n  .hero-landing-subtitle {\n    font-size: 0.9rem;\n  }\n\n  .hero-landing-description {\n    font-size: 1rem;\n    margin-bottom: 30px;\n  }\n\n  .hero-landing-boxes {\n    grid-template-columns: 1fr;\n  }\n\n  .section-white,\n  .section-beige {\n    padding: 50px 15px;\n  }\n\n  .section-title {\n    font-size: 1.6rem;\n    margin-bottom: 15px;\n  }\n\n  .section-intro {\n    font-size: 1rem;\n  }\n\n  .text-content {\n    font-size: 1rem;\n  }\n\n  .grid-quartiers {\n    grid-template-columns: 1fr;\n    gap: 15px;\n  }\n\n  .card-quartier {\n    padding: 20px 15px;\n  }\n\n  .card-quartier h3 {\n    font-size: 1.3rem;\n  }\n\n  .card-quartier p {\n    font-size: 0.9rem;\n  }\n\n  .market-stats {\n    grid-template-columns: 1fr;\n    gap: 15px;\n  }\n\n  .stat-item {\n    padding: 20px;\n  }\n\n  .stat-value {\n    font-size: 1.5rem;\n  }\n\n  .quality-of-life {\n    grid-template-columns: 1fr;\n    gap: 20px;\n  }\n\n  .qol-item {\n    gap: 12px;\n  }\n\n  .qol-icon {\n    font-size: 1.8rem;\n  }\n\n  .qol-item h4 {\n    font-size: 1.05rem;\n  }\n\n  .qol-item p {\n    font-size: 0.9rem;\n  }\n\n  .cta-final {\n    padding: 60px 15px;\n  }\n\n  .cta-final h2 {\n    font-size: 1.5rem;\n  }\n\n  .cta-btn,\n  .cta-btn-large {\n    padding: 12px 25px;\n    font-size: 1rem;\n  }\n\n  .highlight-box {\n    padding: 20px;\n    margin: 30px 0;\n  }\n\n  .highlight-box h3 {\n    font-size: 1.1rem;\n  }\n\n  .highlight-box p {\n    font-size: 0.9rem;\n  }\n}', '', 'ia', NULL, NULL, 0, 'Secteurs', '', 'principal', 'principal', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'frontend', 'public', 'published', 1, 1, '2026-02-04 14:01:26', NULL, '2026-02-09 02:32:42', NULL, 5, 90, 0, 0, 0, 'default', 'page', 'page', 'default', NULL, NULL, NULL, NULL, NULL, NULL, 'Quartiers Bordeaux Métropole | Immobilier & Investissement', 'Découvrez les quartiers de Bordeaux Métropole. Prix 4000-6500€/m². 4e ville la plus attractive de France. Trouvez votre futur investissement !', 'quartiers Bordeaux, immobilier Bordeaux, investissement Bordeaux, Bordeaux Métropole, prix immobilier Bordeaux, secteurs Bordeaux, marché immobilier Bordeaux', NULL, 'secteurs', 'Explorez les quartiers de Bordeaux Métropole, 4e ville la plus attractive de France avec des prix de 4000 à 6500€/m².', NULL, NULL, 0, NULL, 'sections', '', NULL, NULL, NULL, NULL, NULL, NULL, '2026-02-08 03:39:53', '[\"Titre: longueur non optimale\"]', 1, 1, 1, 1, 1, '', 'index, follow', 0, 0, NULL, NULL, NULL, NULL);
INSERT INTO `pages` (`id`, `website_id`, `template_id`, `title`, `excerpt`, `slug`, `template`, `show_header`, `show_footer`, `show_nav`, `content`, `custom_css`, `custom_js`, `builder_mode`, `builder_data`, `file_path`, `is_file_based`, `meta_title`, `meta_description`, `header_type`, `footer_type`, `header_custom`, `footer_custom`, `h1`, `focus_keyword`, `ai_description`, `featured_image`, `category`, `tags`, `content_type`, `page_category`, `page_type`, `status`, `header_enabled`, `footer_enabled`, `created_at`, `created_by`, `updated_at`, `published_at`, `reading_time`, `seo_score`, `views`, `serp_position`, `visitors`, `template_name`, `type`, `layout`, `layout_template`, `hero_data`, `sections_data`, `sidebar_data`, `cta_data`, `quartier_data`, `breadcrumb`, `seo_title`, `seo_description`, `seo_keywords`, `inline_css`, `canonical_url`, `description`, `settings_data`, `serp_keyword`, `is_indexed`, `last_seo_check`, `editor_type`, `og_image`, `external_css`, `external_js`, `secondary_keywords`, `last_serp_check`, `last_index_check`, `index_checked_at`, `seo_analyzed_at`, `seo_issues`, `use_global_css`, `use_global_header`, `use_global_footer`, `header_id`, `footer_id`, `meta_keywords`, `meta_robots`, `noindex`, `seo_validated`, `seo_validated_at`, `semantic_score`, `semantic_data`, `semantic_analyzed_at`) VALUES
(74, NULL, NULL, 'Merci Estimation', NULL, '/merci-estimation', 'default', 1, 1, 1, '<!-- ═══ HERO CONFIRMATION ═══ -->\n<section class=\"thankyou-hero\">\n    <div class=\"thankyou-container\">\n        <div class=\"success-icon\">\n            <i class=\"fas fa-check\"></i>\n        </div>\n\n        <h1 class=\"thankyou-title\">\n            Merci <span class=\"gold\" id=\"leadName\"></span> !\n        </h1>\n\n        <p class=\"thankyou-subtitle\">\n            Votre demande d\'estimation gratuite a bien été enregistrée.<br>\n            Eduardo De Sul vous recontactera personnellement sous <strong>24 heures</strong>.\n        </p>\n\n        <div class=\"ref-badge\" id=\"refBadge\" style=\"display:none;\">\n            <i class=\"fas fa-hashtag\"></i>\n            Référence : <strong id=\"refValue\"></strong>\n        </div>\n    </div>\n</section>\n\n<!-- ═══ ÉTAPES SUIVANTES ═══ -->\n<section class=\"steps-section\">\n    <div class=\"steps-card\">\n        <h2 class=\"steps-title\">Les prochaines étapes</h2>\n\n        <div class=\"steps-grid\">\n            <div class=\"step step-done\">\n                <div class=\"step-number\">\n                    <i class=\"fas fa-check\"></i>\n                </div>\n                <div class=\"step-line\"></div>\n                <h3>Demande reçue</h3>\n                <p>Votre demande d\'estimation est bien enregistrée dans notre système.</p>\n                <span class=\"step-tag done\">✓ Confirmé</span>\n            </div>\n\n            <div class=\"step step-active\">\n                <div class=\"step-number\">2</div>\n                <div class=\"step-line\"></div>\n                <h3>Analyse du bien</h3>\n                <p>Eduardo analyse les données du marché bordelais pour votre bien.</p>\n                <span class=\"step-tag active\">⏱ Sous 24h</span>\n            </div>\n\n            <div class=\"step step-pending\">\n                <div class=\"step-number\">3</div>\n                <h3>Votre estimation</h3>\n                <p>Vous recevrez une estimation détaillée et personnalisée.</p>\n                <span class=\"step-tag pending\">📧 Par email & téléphone</span>\n            </div>\n        </div>\n    </div>\n</section>\n\n<!-- ═══ CONSEILLER + ACTIONS ═══ -->\n<section class=\"info-section\">\n    <!-- Carte conseiller -->\n    <div class=\"info-card card-advisor\">\n        <div class=\"card-header-icon\">\n            <div class=\"card-icon icon-primary\"><i class=\"fas fa-user-tie\"></i></div>\n            <div>\n                <h3>Votre conseiller dédié</h3>\n                <span class=\"card-subtitle\">Expert marché bordelais</span>\n            </div>\n        </div>\n\n        <div class=\"advisor-profile\">\n            <div class=\"advisor-photo\">\n                <img src=\"/assets/images/eduardo-desul.jpg\" alt=\"Eduardo De Sul\" onerror=\"this.style.display=\'none\'; this.nextElementSibling.style.display=\'flex\';\">\n                <div class=\"advisor-photo-fallback\" style=\"display:none;\"><i class=\"fas fa-user-tie\"></i></div>\n            </div>\n            <div class=\"advisor-info\">\n                <strong>Eduardo De Sul</strong>\n                <span>Conseiller immobilier indépendant</span>\n                <span class=\"advisor-network\"><i class=\"fas fa-building\"></i> eXp France — Bordeaux</span>\n            </div>\n        </div>\n\n        <div class=\"contact-lines\">\n            <a href=\"tel:+33600000000\" class=\"contact-line\">\n                <i class=\"fas fa-phone\"></i>\n                <span>06 XX XX XX XX</span>\n            </a>\n            <a href=\"mailto:eduardo@eduardo-desul-immobilier.fr\" class=\"contact-line\">\n                <i class=\"fas fa-envelope\"></i>\n                <span>eduardo@eduardo-desul-immobilier.fr</span>\n            </a>\n            <a href=\"https://wa.me/33600000000\" class=\"contact-line whatsapp\" target=\"_blank\">\n                <i class=\"fab fa-whatsapp\"></i>\n                <span>Écrire sur WhatsApp</span>\n            </a>\n        </div>\n    </div>\n\n    <!-- Carte actions -->\n    <div class=\"info-card card-explore\">\n        <div class=\"card-header-icon\">\n            <div class=\"card-icon icon-gold\"><i class=\"fas fa-compass\"></i></div>\n            <div>\n                <h3>En attendant votre estimation</h3>\n                <span class=\"card-subtitle\">Explorez vos options</span>\n            </div>\n        </div>\n\n        <p class=\"explore-text\">\n            Découvrez les quartiers de Bordeaux, consultez les biens disponibles et préparez votre projet immobilier.\n        </p>\n\n        <div class=\"explore-links\">\n            <a href=\"/secteurs\" class=\"explore-link\">\n                <div class=\"explore-link-icon\"><i class=\"fas fa-map-marked-alt\"></i></div>\n                <div>\n                    <strong>Quartiers de Bordeaux</strong>\n                    <span>Prix, ambiance, transports…</span>\n                </div>\n                <i class=\"fas fa-chevron-right\"></i>\n            </a>\n            <a href=\"/acheter\" class=\"explore-link\">\n                <div class=\"explore-link-icon\"><i class=\"fas fa-home\"></i></div>\n                <div>\n                    <strong>Biens à vendre</strong>\n                    <span>Appartements & maisons</span>\n                </div>\n                <i class=\"fas fa-chevron-right\"></i>\n            </a>\n            <a href=\"/vendre\" class=\"explore-link\">\n                <div class=\"explore-link-icon\"><i class=\"fas fa-hand-holding-usd\"></i></div>\n                <div>\n                    <strong>Guide vendeur</strong>\n                    <span>Conseils pour bien vendre</span>\n                </div>\n                <i class=\"fas fa-chevron-right\"></i>\n            </a>\n        </div>\n\n        <a href=\"/\" class=\"btn-back-home\">\n            <i class=\"fas fa-arrow-left\"></i> Retour à l\'accueil\n        </a>\n    </div>\n</section>\n\n<!-- ═══ TRUST BAR ═══ -->\n<section class=\"trust-section\">\n    <div class=\"trust-bar\">\n        <div class=\"trust-item\">\n            <div class=\"trust-number\">200+</div>\n            <div class=\"trust-label\">Estimations réalisées</div>\n        </div>\n        <div class=\"trust-divider\"></div>\n        <div class=\"trust-item\">\n            <div class=\"trust-number\">98%</div>\n            <div class=\"trust-label\">Clients satisfaits</div>\n        </div>\n        <div class=\"trust-divider\"></div>\n        <div class=\"trust-item\">\n            <div class=\"trust-number\">24h</div>\n            <div class=\"trust-label\">Délai de réponse</div>\n        </div>\n        <div class=\"trust-divider\"></div>\n        <div class=\"trust-item\">\n            <div class=\"trust-number\">100%</div>\n            <div class=\"trust-label\">Gratuit & sans engagement</div>\n        </div>\n    </div>\n</section>', '/* ═══════════════════════════════════════════════\n   MERCI ESTIMATION — Page de remerciement\n   Builder Pro CSS — Coller dans l\'onglet CSS\n   ═══════════════════════════════════════════════ */\n\n/* ─── Variables ─── */\n:root {\n    --ty-primary: #1e3a5f;\n    --ty-primary-light: #2a4f7f;\n    --ty-gold: #c8a96e;\n    --ty-gold-light: #d4bc8e;\n    --ty-gold-glow: rgba(200, 169, 110, 0.15);\n    --ty-text: #334155;\n    --ty-text-light: #64748b;\n    --ty-bg: #f8fafc;\n    --ty-white: #ffffff;\n    --ty-success: #10b981;\n    --ty-success-light: #d1fae5;\n    --ty-border: #e2e8f0;\n    --ty-radius: 14px;\n}\n\n/* ═══ HERO ═══ */\n.thankyou-hero {\n    background: linear-gradient(145deg, var(--ty-primary) 0%, var(--ty-primary-light) 40%, #162d4a 100%);\n    padding: 90px 20px 70px;\n    text-align: center;\n    position: relative;\n    overflow: hidden;\n}\n\n.thankyou-hero::before {\n    content: \'\';\n    position: absolute;\n    inset: 0;\n    background:\n        radial-gradient(ellipse at 25% 40%, rgba(200, 169, 110, 0.1) 0%, transparent 55%),\n        radial-gradient(ellipse at 75% 70%, rgba(255,255,255,0.04) 0%, transparent 50%);\n    pointer-events: none;\n}\n\n.thankyou-hero::after {\n    content: \'\';\n    position: absolute;\n    bottom: 0;\n    left: 0;\n    right: 0;\n    height: 60px;\n    background: linear-gradient(to top, var(--ty-bg), transparent);\n}\n\n.thankyou-container {\n    max-width: 680px;\n    margin: 0 auto;\n    position: relative;\n    z-index: 1;\n}\n\n/* ─── Icône succès ─── */\n.success-icon {\n    width: 96px;\n    height: 96px;\n    background: linear-gradient(135deg, var(--ty-gold), var(--ty-gold-light));\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    margin: 0 auto 30px;\n    animation: heroScaleIn 0.7s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;\n    box-shadow:\n        0 0 0 10px rgba(200, 169, 110, 0.12),\n        0 0 0 22px rgba(200, 169, 110, 0.06),\n        0 8px 32px rgba(200, 169, 110, 0.25);\n}\n\n.success-icon i {\n    font-size: 42px;\n    color: var(--ty-white);\n    animation: heroCheckIn 0.5s ease 0.35s both;\n}\n\n@keyframes heroScaleIn {\n    from { transform: scale(0) rotate(-20deg); opacity: 0; }\n    to   { transform: scale(1) rotate(0deg); opacity: 1; }\n}\n\n@keyframes heroCheckIn {\n    from { transform: scale(0) rotate(-30deg); opacity: 0; }\n    to   { transform: scale(1) rotate(0deg); opacity: 1; }\n}\n\n/* ─── Titre ─── */\n.thankyou-title {\n    font-family: \'Playfair Display\', Georgia, serif;\n    font-size: 2.4rem;\n    font-weight: 700;\n    color: var(--ty-white);\n    margin-bottom: 14px;\n    animation: heroFadeUp 0.6s ease 0.2s both;\n    letter-spacing: -0.02em;\n}\n\n.thankyou-title .gold {\n    color: var(--ty-gold);\n}\n\n.thankyou-subtitle {\n    font-size: 1.15rem;\n    color: rgba(255, 255, 255, 0.78);\n    line-height: 1.7;\n    max-width: 540px;\n    margin: 0 auto;\n    animation: heroFadeUp 0.6s ease 0.35s both;\n}\n\n.thankyou-subtitle strong {\n    color: var(--ty-gold-light);\n}\n\n@keyframes heroFadeUp {\n    from { transform: translateY(24px); opacity: 0; }\n    to   { transform: translateY(0); opacity: 1; }\n}\n\n/* ─── Ref badge ─── */\n.ref-badge {\n    display: inline-flex;\n    align-items: center;\n    gap: 8px;\n    background: rgba(255, 255, 255, 0.08);\n    border: 1px solid rgba(200, 169, 110, 0.25);\n    border-radius: 30px;\n    padding: 9px 22px;\n    margin-top: 26px;\n    font-size: 0.9rem;\n    color: var(--ty-gold-light);\n    animation: heroFadeUp 0.6s ease 0.5s both;\n    backdrop-filter: blur(6px);\n    -webkit-backdrop-filter: blur(6px);\n}\n\n.ref-badge i {\n    font-size: 0.75rem;\n    opacity: 0.6;\n}\n\n/* ═══ ÉTAPES ═══ */\n.steps-section {\n    max-width: 920px;\n    margin: -32px auto 0;\n    padding: 0 20px;\n    position: relative;\n    z-index: 2;\n}\n\n.steps-card {\n    background: var(--ty-white);\n    border-radius: var(--ty-radius);\n    box-shadow: 0 4px 35px rgba(30, 58, 95, 0.08), 0 1px 3px rgba(0, 0, 0, 0.03);\n    padding: 44px 40px;\n    animation: heroFadeUp 0.6s ease 0.45s both;\n}\n\n.steps-title {\n    text-align: center;\n    font-family: \'Playfair Display\', Georgia, serif;\n    font-size: 1.5rem;\n    color: var(--ty-primary);\n    margin-bottom: 40px;\n    font-weight: 600;\n}\n\n.steps-grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 0;\n}\n\n.step {\n    text-align: center;\n    padding: 0 20px;\n    position: relative;\n}\n\n/* Lignes entre étapes */\n.step .step-line {\n    position: absolute;\n    top: 26px;\n    left: 60%;\n    width: 80%;\n    height: 2px;\n    background: linear-gradient(90deg, var(--ty-gold) 50%, var(--ty-border) 50%);\n    background-size: 8px 2px;\n    opacity: 0.4;\n}\n\n.step:last-child .step-line {\n    display: none;\n}\n\n.step-number {\n    width: 54px;\n    height: 54px;\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    margin: 0 auto 16px;\n    font-size: 1.15rem;\n    font-weight: 700;\n    position: relative;\n    z-index: 1;\n    transition: all 0.3s ease;\n}\n\n.step-done .step-number {\n    background: var(--ty-success);\n    color: var(--ty-white);\n    box-shadow: 0 0 0 5px var(--ty-success-light);\n}\n\n.step-active .step-number {\n    background: var(--ty-gold);\n    color: var(--ty-white);\n    box-shadow: 0 0 0 5px var(--ty-gold-glow);\n    animation: stepPulse 2.5s ease-in-out infinite;\n}\n\n.step-pending .step-number {\n    background: #f1f5f9;\n    color: var(--ty-text-light);\n    border: 2px dashed var(--ty-border);\n}\n\n@keyframes stepPulse {\n    0%, 100% { box-shadow: 0 0 0 5px rgba(200,169,110,0.15); }\n    50%      { box-shadow: 0 0 0 10px rgba(200,169,110,0.06); }\n}\n\n.step h3 {\n    font-size: 1rem;\n    font-weight: 600;\n    color: var(--ty-primary);\n    margin-bottom: 6px;\n}\n\n.step p {\n    font-size: 0.88rem;\n    color: var(--ty-text-light);\n    line-height: 1.5;\n    margin-bottom: 10px;\n}\n\n.step-tag {\n    display: inline-block;\n    font-size: 0.78rem;\n    font-weight: 600;\n    padding: 4px 12px;\n    border-radius: 20px;\n}\n\n.step-tag.done {\n    background: var(--ty-success-light);\n    color: #065f46;\n}\n\n.step-tag.active {\n    background: var(--ty-gold-glow);\n    color: #92702d;\n}\n\n.step-tag.pending {\n    background: #f1f5f9;\n    color: var(--ty-text-light);\n}\n\n/* ═══ SECTION INFO ═══ */\n.info-section {\n    max-width: 920px;\n    margin: 40px auto;\n    padding: 0 20px;\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 24px;\n    animation: heroFadeUp 0.6s ease 0.6s both;\n}\n\n.info-card {\n    background: var(--ty-white);\n    border-radius: var(--ty-radius);\n    padding: 32px;\n    box-shadow: 0 2px 16px rgba(0, 0, 0, 0.03);\n    border: 1px solid var(--ty-border);\n    transition: all 0.3s ease;\n}\n\n.info-card:hover {\n    box-shadow: 0 8px 35px rgba(30, 58, 95, 0.07);\n    transform: translateY(-3px);\n}\n\n.card-header-icon {\n    display: flex;\n    align-items: center;\n    gap: 14px;\n    margin-bottom: 22px;\n}\n\n.card-header-icon h3 {\n    font-family: \'Playfair Display\', Georgia, serif;\n    font-size: 1.15rem;\n    color: var(--ty-primary);\n    margin: 0;\n    line-height: 1.2;\n}\n\n.card-subtitle {\n    font-size: 0.82rem;\n    color: var(--ty-text-light);\n}\n\n.card-icon {\n    width: 48px;\n    height: 48px;\n    border-radius: 12px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 1.2rem;\n    flex-shrink: 0;\n}\n\n.icon-primary {\n    background: linear-gradient(135deg, var(--ty-primary), var(--ty-primary-light));\n    color: var(--ty-white);\n}\n\n.icon-gold {\n    background: linear-gradient(135deg, var(--ty-gold), var(--ty-gold-light));\n    color: var(--ty-white);\n}\n\n/* ─── Profil conseiller ─── */\n.advisor-profile {\n    display: flex;\n    align-items: center;\n    gap: 16px;\n    padding: 16px;\n    background: #f8fafc;\n    border-radius: 12px;\n    margin-bottom: 20px;\n}\n\n.advisor-photo {\n    width: 60px;\n    height: 60px;\n    border-radius: 50%;\n    overflow: hidden;\n    flex-shrink: 0;\n    border: 3px solid var(--ty-gold-glow);\n}\n\n.advisor-photo img {\n    width: 100%;\n    height: 100%;\n    object-fit: cover;\n}\n\n.advisor-photo-fallback {\n    width: 100%;\n    height: 100%;\n    background: var(--ty-primary);\n    align-items: center;\n    justify-content: center;\n    color: var(--ty-gold);\n    font-size: 1.5rem;\n}\n\n.advisor-info {\n    display: flex;\n    flex-direction: column;\n    gap: 2px;\n}\n\n.advisor-info strong {\n    font-size: 1rem;\n    color: var(--ty-primary);\n}\n\n.advisor-info span {\n    font-size: 0.85rem;\n    color: var(--ty-text-light);\n}\n\n.advisor-network {\n    font-size: 0.8rem !important;\n    color: var(--ty-gold) !important;\n    display: flex;\n    align-items: center;\n    gap: 5px;\n    margin-top: 2px;\n}\n\n/* ─── Lignes de contact ─── */\n.contact-lines {\n    display: flex;\n    flex-direction: column;\n    gap: 0;\n}\n\n.contact-line {\n    display: flex;\n    align-items: center;\n    gap: 12px;\n    padding: 13px 14px;\n    border-bottom: 1px solid #f1f5f9;\n    font-size: 0.93rem;\n    color: var(--ty-text);\n    text-decoration: none;\n    transition: all 0.2s ease;\n    border-radius: 8px;\n}\n\n.contact-line:hover {\n    background: #f8fafc;\n    color: var(--ty-gold);\n    transform: translateX(4px);\n}\n\n.contact-line:last-child {\n    border-bottom: none;\n}\n\n.contact-line i {\n    color: var(--ty-gold);\n    width: 22px;\n    text-align: center;\n    font-size: 1rem;\n}\n\n.contact-line.whatsapp:hover {\n    color: #25d366;\n}\n\n.contact-line.whatsapp i {\n    color: #25d366;\n}\n\n/* ─── Carte Explorer ─── */\n.explore-text {\n    font-size: 0.93rem;\n    color: var(--ty-text-light);\n    line-height: 1.6;\n    margin-bottom: 20px;\n}\n\n.explore-links {\n    display: flex;\n    flex-direction: column;\n    gap: 8px;\n    margin-bottom: 20px;\n}\n\n.explore-link {\n    display: flex;\n    align-items: center;\n    gap: 14px;\n    padding: 14px 16px;\n    background: #f8fafc;\n    border: 1px solid var(--ty-border);\n    border-radius: 10px;\n    text-decoration: none;\n    color: var(--ty-text);\n    transition: all 0.25s ease;\n}\n\n.explore-link:hover {\n    border-color: var(--ty-gold);\n    background: var(--ty-gold-glow);\n    transform: translateX(4px);\n    box-shadow: 0 4px 15px rgba(200, 169, 110, 0.1);\n}\n\n.explore-link:hover .explore-link-icon {\n    background: var(--ty-gold);\n    color: var(--ty-white);\n}\n\n.explore-link-icon {\n    width: 40px;\n    height: 40px;\n    border-radius: 10px;\n    background: #e2e8f0;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    flex-shrink: 0;\n    color: var(--ty-primary);\n    transition: all 0.25s ease;\n}\n\n.explore-link div strong {\n    display: block;\n    font-size: 0.92rem;\n    color: var(--ty-primary);\n}\n\n.explore-link div span {\n    font-size: 0.8rem;\n    color: var(--ty-text-light);\n}\n\n.explore-link > .fa-chevron-right {\n    margin-left: auto;\n    color: var(--ty-border);\n    font-size: 0.75rem;\n    transition: all 0.2s;\n}\n\n.explore-link:hover > .fa-chevron-right {\n    color: var(--ty-gold);\n    transform: translateX(3px);\n}\n\n.btn-back-home {\n    display: inline-flex;\n    align-items: center;\n    gap: 8px;\n    padding: 10px 20px;\n    border: 2px solid var(--ty-border);\n    border-radius: 8px;\n    font-size: 0.9rem;\n    font-weight: 500;\n    color: var(--ty-text-light);\n    text-decoration: none;\n    transition: all 0.2s ease;\n}\n\n.btn-back-home:hover {\n    border-color: var(--ty-primary);\n    color: var(--ty-primary);\n}\n\n/* ═══ TRUST BAR ═══ */\n.trust-section {\n    max-width: 920px;\n    margin: 0 auto 60px;\n    padding: 0 20px;\n    animation: heroFadeUp 0.6s ease 0.75s both;\n}\n\n.trust-bar {\n    background: var(--ty-white);\n    border-radius: var(--ty-radius);\n    padding: 26px 40px;\n    display: flex;\n    justify-content: space-around;\n    align-items: center;\n    box-shadow: 0 2px 16px rgba(0, 0, 0, 0.03);\n    border: 1px solid var(--ty-border);\n}\n\n.trust-item {\n    text-align: center;\n}\n\n.trust-number {\n    font-family: \'Playfair Display\', Georgia, serif;\n    font-size: 1.7rem;\n    font-weight: 700;\n    color: var(--ty-primary);\n    line-height: 1;\n}\n\n.trust-label {\n    font-size: 0.8rem;\n    color: var(--ty-text-light);\n    margin-top: 5px;\n}\n\n.trust-divider {\n    width: 1px;\n    height: 42px;\n    background: var(--ty-border);\n}\n\n/* ═══ RESPONSIVE ═══ */\n@media (max-width: 768px) {\n    .thankyou-hero {\n        padding: 70px 20px 55px;\n    }\n\n    .thankyou-title {\n        font-size: 1.8rem;\n    }\n\n    .thankyou-subtitle {\n        font-size: 1.05rem;\n    }\n\n    .steps-card {\n        padding: 32px 22px;\n    }\n\n    .steps-grid {\n        grid-template-columns: 1fr;\n        gap: 28px;\n    }\n\n    .step .step-line {\n        display: none;\n    }\n\n    .info-section {\n        grid-template-columns: 1fr;\n        gap: 20px;\n    }\n\n    .trust-bar {\n        flex-wrap: wrap;\n        gap: 20px;\n        padding: 24px 20px;\n    }\n\n    .trust-divider {\n        display: none;\n    }\n\n    .trust-item {\n        width: 45%;\n    }\n}\n\n@media (max-width: 480px) {\n    .thankyou-hero {\n        padding: 55px 16px 45px;\n    }\n\n    .thankyou-title {\n        font-size: 1.5rem;\n    }\n\n    .success-icon {\n        width: 76px;\n        height: 76px;\n    }\n\n    .success-icon i {\n        font-size: 34px;\n    }\n\n    .info-card {\n        padding: 24px 20px;\n    }\n\n    .advisor-profile {\n        flex-direction: column;\n        text-align: center;\n    }\n\n    .trust-item {\n        width: 100%;\n    }\n}', '/* ═══════════════════════════════════════════════\n   MERCI ESTIMATION — JavaScript\n   Builder Pro JS — Coller dans l\'onglet JS\n   ═══════════════════════════════════════════════ */\n\ndocument.addEventListener(\'DOMContentLoaded\', function() {\n\n    // ─── 1. Récupérer les paramètres URL ───\n    const params = new URLSearchParams(window.location.search);\n    const ref       = params.get(\'ref\') || \'\';\n    const firstName = params.get(\'prenom\') || params.get(\'first_name\') || \'\';\n    const lastName  = params.get(\'nom\') || params.get(\'last_name\') || \'\';\n    const email     = params.get(\'email\') || \'\';\n    const phone     = params.get(\'tel\') || params.get(\'phone\') || \'\';\n\n    // ─── 2. Personnaliser le nom ───\n    const nameEl = document.getElementById(\'leadName\');\n    if (nameEl) {\n        const fullName = [firstName, lastName].filter(Boolean).join(\' \').trim();\n        if (fullName) {\n            nameEl.textContent = fullName;\n        } else {\n            // Pas de nom → afficher un message générique\n            nameEl.textContent = \'\';\n        }\n    }\n\n    // ─── 3. Afficher la référence ───\n    const refBadge = document.getElementById(\'refBadge\');\n    const refValue = document.getElementById(\'refValue\');\n    if (ref && refBadge && refValue) {\n        refValue.textContent = ref;\n        refBadge.style.display = \'inline-flex\';\n    }\n\n    // ─── 4. Animation d\'entrée séquentielle ───\n    const animatedElements = document.querySelectorAll(\n        \'.steps-section, .info-card, .trust-section\'\n    );\n\n    if (\'IntersectionObserver\' in window) {\n        const observer = new IntersectionObserver(function(entries) {\n            entries.forEach(function(entry) {\n                if (entry.isIntersecting) {\n                    entry.target.classList.add(\'visible\');\n                    observer.unobserve(entry.target);\n                }\n            });\n        }, { threshold: 0.15 });\n\n        animatedElements.forEach(function(el) {\n            el.style.opacity = \'0\';\n            el.style.transform = \'translateY(20px)\';\n            el.style.transition = \'opacity 0.6s ease, transform 0.6s ease\';\n            observer.observe(el);\n        });\n    }\n\n    // Classe pour éléments visibles\n    const style = document.createElement(\'style\');\n    style.textContent = \'.visible { opacity: 1 !important; transform: translateY(0) !important; }\';\n    document.head.appendChild(style);\n\n    // ─── 5. Tracking de conversion (GTM / GA4 / FB) ───\n    // Google Analytics 4 — event\n    if (typeof gtag === \'function\') {\n        gtag(\'event\', \'generate_lead\', {\n            event_category: \'estimation\',\n            event_label: ref || \'estimation-gratuite\',\n            value: 1\n        });\n    }\n\n    // Facebook Pixel\n    if (typeof fbq === \'function\') {\n        fbq(\'track\', \'Lead\', {\n            content_name: \'Estimation Gratuite Bordeaux\',\n            content_category: \'estimation\'\n        });\n    }\n\n    // GTM dataLayer\n    if (window.dataLayer) {\n        window.dataLayer.push({\n            event: \'estimation_lead\',\n            lead_ref: ref,\n            lead_source: \'estimation-gratuite\'\n        });\n    }\n\n    // ─── 6. Confetti effect léger (optionnel) ───\n    function createConfetti() {\n        const colors = [\'#c8a96e\', \'#1e3a5f\', \'#10b981\', \'#d4bc8e\', \'#3b82f6\'];\n        const container = document.querySelector(\'.thankyou-hero\');\n        if (!container) return;\n\n        for (let i = 0; i < 30; i++) {\n            const confetti = document.createElement(\'div\');\n            confetti.style.cssText = `\n                position: absolute;\n                width: ${Math.random() * 8 + 4}px;\n                height: ${Math.random() * 8 + 4}px;\n                background: ${colors[Math.floor(Math.random() * colors.length)]};\n                border-radius: ${Math.random() > 0.5 ? \'50%\' : \'2px\'};\n                top: -10px;\n                left: ${Math.random() * 100}%;\n                opacity: 0;\n                pointer-events: none;\n                z-index: 0;\n                animation: confettiFall ${Math.random() * 2 + 2}s ease ${Math.random() * 0.8}s forwards;\n            `;\n            container.appendChild(confetti);\n        }\n\n        // Ajouter l\'animation\n        const confettiStyle = document.createElement(\'style\');\n        confettiStyle.textContent = `\n            @keyframes confettiFall {\n                0%   { opacity: 1; transform: translateY(0) rotate(0deg); }\n                100% { opacity: 0; transform: translateY(350px) rotate(${Math.random() * 360}deg); }\n            }\n        `;\n        document.head.appendChild(confettiStyle);\n\n        // Nettoyer après l\'animation\n        setTimeout(function() {\n            container.querySelectorAll(\'[style*=\"confettiFall\"]\').forEach(function(el) {\n                el.remove();\n            });\n        }, 4000);\n    }\n\n    // Lancer les confettis au chargement\n    setTimeout(createConfetti, 600);\n\n    // ─── 7. Console log pour debug ───\n    console.log(\'[Merci Estimation]\', {\n        ref: ref,\n        firstName: firstName,\n        lastName: lastName,\n        email: email ? \'***\' : \'\',\n        phone: phone ? \'***\' : \'\'\n    });\n\n});', 'ia', NULL, NULL, 0, 'Merci Estimation', '', 'principal', 'principal', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'frontend', 'public', 'published', 1, 1, '2026-02-08 13:52:54', NULL, '2026-02-08 12:56:38', NULL, 5, 0, 0, 0, 0, 'default', 'page', 'page', 'default', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, NULL, 0, NULL, 'sections', '', '[]', '[]', NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 1, NULL, NULL, '', 'index, follow', 0, 0, NULL, NULL, NULL, NULL);
INSERT INTO `pages` (`id`, `website_id`, `template_id`, `title`, `excerpt`, `slug`, `template`, `show_header`, `show_footer`, `show_nav`, `content`, `custom_css`, `custom_js`, `builder_mode`, `builder_data`, `file_path`, `is_file_based`, `meta_title`, `meta_description`, `header_type`, `footer_type`, `header_custom`, `footer_custom`, `h1`, `focus_keyword`, `ai_description`, `featured_image`, `category`, `tags`, `content_type`, `page_category`, `page_type`, `status`, `header_enabled`, `footer_enabled`, `created_at`, `created_by`, `updated_at`, `published_at`, `reading_time`, `seo_score`, `views`, `serp_position`, `visitors`, `template_name`, `type`, `layout`, `layout_template`, `hero_data`, `sections_data`, `sidebar_data`, `cta_data`, `quartier_data`, `breadcrumb`, `seo_title`, `seo_description`, `seo_keywords`, `inline_css`, `canonical_url`, `description`, `settings_data`, `serp_keyword`, `is_indexed`, `last_seo_check`, `editor_type`, `og_image`, `external_css`, `external_js`, `secondary_keywords`, `last_serp_check`, `last_index_check`, `index_checked_at`, `seo_analyzed_at`, `seo_issues`, `use_global_css`, `use_global_header`, `use_global_footer`, `header_id`, `footer_id`, `meta_keywords`, `meta_robots`, `noindex`, `seo_validated`, `seo_validated_at`, `semantic_score`, `semantic_data`, `semantic_analyzed_at`) VALUES
(77, NULL, 5, 'Blog', NULL, 'blog', 'standard', 1, 1, 1, '<!-- ================================================\n    TEMPLATE PAGE BLOG — Liste des articles (DYNAMIQUE)\n    CSS : blog-listing.css\n    Variables : {{blog_title}}, {{blog_subtitle}},\n        {{total_articles}}, {{author_name}}, {{author_photo}},\n        {{cta_title}}, {{cta_text}}\n\n    Les articles sont chargés dynamiquement par BlogRenderer\n    depuis la table \"articles\" WHERE status = \'published\'\n   ================================================ -->\n\n<link href=\"https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=Source+Sans+3:wght@300;400;600;700&display=swap\" rel=\"stylesheet\">\n\n<div class=\"blog-listing\">\n\n    <!-- ==============================\n         HERO BANNER\n         ============================== -->\n    <section class=\"bl-hero\">\n        <nav class=\"bl-hero__breadcrumb\" aria-label=\"Fil d\'Ariane\">\n            <a href=\"/\">Accueil</a>\n            <span class=\"sep\">›</span>\n            <span>Blog</span>\n        </nav>\n        <h1 class=\"bl-hero__title\">{{blog_title}}</h1>\n        <p class=\"bl-hero__subtitle\">{{blog_subtitle}}</p>\n    </section>\n\n    <!-- ==============================\n         FILTRES PAR CATÉGORIE\n         ============================== -->\n    <nav class=\"bl-filters\">\n        <div class=\"bl-filters__inner\">\n            <ul class=\"bl-filters__categories\">\n                <li><a class=\"bl-filters__cat active\" href=\"/blog\" data-cat=\"all\">\n                    Tous <span class=\"bl-filters__count\">{{total_articles}}</span>\n                </a></li>\n                <li><a class=\"bl-filters__cat\" href=\"/blog?cat=marche\" data-cat=\"marche\">Marché</a></li>\n                <li><a class=\"bl-filters__cat\" href=\"/blog?cat=acheter\" data-cat=\"acheter\">Acheter</a></li>\n                <li><a class=\"bl-filters__cat\" href=\"/blog?cat=vendre\" data-cat=\"vendre\">Vendre</a></li>\n                <li><a class=\"bl-filters__cat\" href=\"/blog?cat=investir\" data-cat=\"investir\">Investir</a></li>\n                <li><a class=\"bl-filters__cat\" href=\"/blog?cat=quartiers\" data-cat=\"quartiers\">Quartiers</a></li>\n                <li><a class=\"bl-filters__cat\" href=\"/blog?cat=conseils\" data-cat=\"conseils\">Conseils</a></li>\n            </ul>\n            <div class=\"bl-filters__search\">\n                <svg class=\"bl-filters__search-icon\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"11\" cy=\"11\" r=\"8\"/><path d=\"m21 21-4.35-4.35\"/></svg>\n                <input type=\"text\" placeholder=\"Rechercher un article...\" id=\"blogSearch\">\n            </div>\n        </div>\n    </nav>\n\n    <!-- ==============================\n         GRILLE D\'ARTICLES (DYNAMIQUE)\n         ============================== -->\n    <div class=\"bl-content\">\n        <div class=\"bl-grid\">\n\n<!-- ARTICLE_LOOP_START -->\n\n            <!-- ═══════════════════════════════════\n                 ARTICLE À LA UNE (1er article, pleine largeur)\n                 BlogRenderer injecte le 1er article publié ici\n                 ═══════════════════════════════════ -->\n            <!-- FEATURED_START -->\n            <article class=\"bl-featured bl-card\" data-cat=\"{{article_categorie}}\">\n                <div class=\"bl-card__image\">\n                    <img src=\"{{article_image}}\"\n                         alt=\"{{article_title}}\" width=\"800\" height=\"500\" loading=\"eager\">\n                    <span class=\"bl-card__badge-cat\">{{article_categorie}}</span>\n                </div>\n                <div class=\"bl-card__wrap\">\n                    <div class=\"bl-card__body\">\n                        <span class=\"bl-featured__label\">\n                            <svg viewBox=\"0 0 24 24\" fill=\"currentColor\" width=\"14\" height=\"14\"><polygon points=\"12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26\"/></svg>\n                            À la une\n                        </span>\n                        <span class=\"bl-card__date\">\n                            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\"/><line x1=\"16\" y1=\"2\" x2=\"16\" y2=\"6\"/><line x1=\"8\" y1=\"2\" x2=\"8\" y2=\"6\"/><line x1=\"3\" y1=\"10\" x2=\"21\" y2=\"10\"/></svg>\n                            {{article_date_long}}\n                        </span>\n                        <h2 class=\"bl-card__title\">\n                            <a href=\"{{article_url}}\">{{article_title}}</a>\n                        </h2>\n                        <p class=\"bl-card__excerpt\">\n                            {{article_excerpt}}\n                        </p>\n                    </div>\n                    <div class=\"bl-card__footer\">\n                        <div class=\"bl-card__author\">\n                            <img class=\"bl-card__author-avatar\" src=\"{{author_photo}}\" alt=\"{{author_name}}\" width=\"32\" height=\"32\">\n                            <span class=\"bl-card__author-name\">{{author_name}}</span>\n                        </div>\n                        <a href=\"{{article_url}}\" class=\"bl-card__cta\">\n                            Lire l\'article\n                            <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M5 12h14\"/><path d=\"M12 5l7 7-7 7\"/></svg>\n                        </a>\n                    </div>\n                </div>\n            </article>\n            <!-- FEATURED_END -->\n\n            <!-- ═══════════════════════════════════\n                 CARD ARTICLE (template réutilisé en boucle)\n                 BlogRenderer duplique ce bloc pour chaque article\n                 ═══════════════════════════════════ -->\n            <!-- ARTICLE_CARD_START -->\n            <article class=\"bl-card\" data-cat=\"{{article_categorie}}\">\n                <a href=\"{{article_url}}\" class=\"bl-card__image-link\">\n                    <div class=\"bl-card__image\">\n                        <img src=\"{{article_image}}\"\n                             alt=\"{{article_title}}\" width=\"600\" height=\"380\" loading=\"lazy\">\n                        <span class=\"bl-card__badge-cat\">{{article_categorie}}</span>\n                        <span class=\"bl-card__time\">{{article_reading_time}} min</span>\n                    </div>\n                </a>\n                <div class=\"bl-card__body\">\n                    <span class=\"bl-card__date\">\n                        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\"/><line x1=\"16\" y1=\"2\" x2=\"16\" y2=\"6\"/><line x1=\"8\" y1=\"2\" x2=\"8\" y2=\"6\"/><line x1=\"3\" y1=\"10\" x2=\"21\" y2=\"10\"/></svg>\n                        {{article_date_long}}\n                    </span>\n                    <h2 class=\"bl-card__title\">\n                        <a href=\"{{article_url}}\">{{article_title}}</a>\n                    </h2>\n                    <p class=\"bl-card__excerpt\">\n                        {{article_excerpt}}\n                    </p>\n                </div>\n                <div class=\"bl-card__footer\">\n                    <div class=\"bl-card__author\">\n                        <img class=\"bl-card__author-avatar\" src=\"{{author_photo}}\" alt=\"{{author_name}}\" width=\"32\" height=\"32\">\n                        <span class=\"bl-card__author-name\">{{author_name}}</span>\n                    </div>\n                    <a href=\"{{article_url}}\" class=\"bl-card__cta\">\n                        Lire\n                        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M5 12h14\"/><path d=\"M12 5l7 7-7 7\"/></svg>\n                    </a>\n                </div>\n            </article>\n            <!-- ARTICLE_CARD_END -->\n\n<!-- ARTICLE_LOOP_END -->\n\n        </div>\n\n        <!-- ════ PAGINATION (générée par BlogRenderer) ════ -->\n        {{pagination}}\n\n        <!-- ════ CTA NEWSLETTER ════ -->\n        <section class=\"bl-newsletter\">\n            <h2 class=\"bl-newsletter__title\">{{cta_title}}</h2>\n            <p class=\"bl-newsletter__text\">{{cta_text}}</p>\n            <form class=\"bl-newsletter__form\" onsubmit=\"return false;\">\n                <input type=\"email\" class=\"bl-newsletter__input\" placeholder=\"Votre adresse email...\" required>\n                <button type=\"submit\" class=\"bl-newsletter__btn\">S\'abonner</button>\n            </form>\n            <p class=\"bl-newsletter__rgpd\">En vous inscrivant, vous acceptez notre politique de confidentialité. Désabonnement en un clic.</p>\n        </section>\n\n    </div>\n</div>\n\n<!-- ════ JS — Filtre catégories + Recherche live ════ -->\n<script>\n(function() {\n    \'use strict\';\n\n    document.addEventListener(\'DOMContentLoaded\', function() {\n\n        // ── Filtres par catégorie (côté client pour rapidité) ──\n        var catLinks = document.querySelectorAll(\'.bl-filters__cat\');\n        var allCards = document.querySelectorAll(\'.bl-card\');\n\n        catLinks.forEach(function(link) {\n            link.addEventListener(\'click\', function(e) {\n                e.preventDefault();\n                catLinks.forEach(function(c) { c.classList.remove(\'active\'); });\n                this.classList.add(\'active\');\n\n                var cat = this.getAttribute(\'data-cat\');\n                allCards.forEach(function(card) {\n                    if (cat === \'all\') {\n                        card.style.display = \'\';\n                    } else {\n                        var cardCat = (card.getAttribute(\'data-cat\') || \'\').toLowerCase();\n                        card.style.display = (cardCat.indexOf(cat) !== -1) ? \'\' : \'none\';\n                    }\n                });\n            });\n        });\n\n        // ── Activer le filtre si ?cat= dans l\'URL ──\n        var urlParams = new URLSearchParams(window.location.search);\n        var activeCat = urlParams.get(\'cat\');\n        if (activeCat) {\n            var target = document.querySelector(\'.bl-filters__cat[data-cat=\"\' + activeCat + \'\"]\');\n            if (target) target.click();\n        }\n\n        // ── Recherche temps réel ──\n        var searchInput = document.getElementById(\'blogSearch\');\n        if (searchInput) {\n            var debounce;\n            searchInput.addEventListener(\'input\', function() {\n                clearTimeout(debounce);\n                var self = this;\n                debounce = setTimeout(function() {\n                    var q = self.value.toLowerCase().trim();\n                    allCards.forEach(function(card) {\n                        if (!q) { card.style.display = \'\'; return; }\n                        var text = (card.textContent || \'\').toLowerCase();\n                        card.style.display = text.indexOf(q) !== -1 ? \'\' : \'none\';\n                    });\n                }, 200);\n            });\n        }\n\n        // ── Animation fade-in au scroll ──\n        if (\'IntersectionObserver\' in window) {\n            var observer = new IntersectionObserver(function(entries) {\n                entries.forEach(function(entry) {\n                    if (entry.isIntersecting) {\n                        entry.target.classList.add(\'bl-card--visible\');\n                        observer.unobserve(entry.target);\n                    }\n                });\n            }, { threshold: 0.08 });\n\n            allCards.forEach(function(card, i) {\n                card.style.transitionDelay = (i * 0.07) + \'s\';\n                observer.observe(card);\n            });\n        } else {\n            allCards.forEach(function(card) { card.classList.add(\'bl-card--visible\'); });\n        }\n    });\n})();\n</script>', '/* ============================================\n   TEMPLATE PAGE BLOG — Liste des articles\n   CSS : blog-listing.css\n   Charte : Eduardo De Sul Immobilier Bordeaux\n   ============================================ */\n\n/* ── Variables ── */\n:root {\n    --bl-primary: #1a3a5c;\n    --bl-primary-light: #24507a;\n    --bl-accent: #c8956c;\n    --bl-accent-hover: #b8854f;\n    --bl-bg: #f7f8fa;\n    --bl-white: #ffffff;\n    --bl-text: #2d3748;\n    --bl-text-light: #718096;\n    --bl-border: #e2e8f0;\n    --bl-shadow: 0 2px 12px rgba(26,58,92,0.08);\n    --bl-shadow-hover: 0 8px 30px rgba(26,58,92,0.15);\n    --bl-radius: 10px;\n    --bl-radius-lg: 16px;\n    --bl-transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);\n    --bl-wide: 1200px;\n    --bl-font-heading: \'Playfair Display\', Georgia, serif;\n    --bl-font-body: \'Source Sans 3\', \'Segoe UI\', sans-serif;\n}\n\n/* ── Base ── */\n.blog-listing {\n    font-family: var(--bl-font-body);\n    color: var(--bl-text);\n    line-height: 1.6;\n    background: var(--bl-bg);\n}\n.blog-listing *, .blog-listing *::before, .blog-listing *::after { box-sizing: border-box; }\n\n/* ══════════════════════════════════════\n   HERO BANNER\n   ══════════════════════════════════════ */\n.bl-hero {\n    background: linear-gradient(135deg, var(--bl-primary) 0%, var(--bl-primary-light) 100%);\n    padding: 60px 24px 50px;\n    text-align: center;\n    position: relative;\n    overflow: hidden;\n}\n.bl-hero::before {\n    content: \'\';\n    position: absolute; top: -50%; right: -10%;\n    width: 500px; height: 500px;\n    background: radial-gradient(circle, rgba(200,149,108,0.12) 0%, transparent 70%);\n    border-radius: 50%;\n}\n\n.bl-hero__breadcrumb {\n    display: flex; align-items: center; justify-content: center; gap: 8px;\n    font-size: 13px; color: rgba(255,255,255,0.6);\n    margin-bottom: 20px; position: relative; z-index: 1;\n}\n.bl-hero__breadcrumb a { color: rgba(255,255,255,0.7); text-decoration: none; transition: color 0.2s; }\n.bl-hero__breadcrumb a:hover { color: var(--bl-accent); }\n.bl-hero__breadcrumb .sep { font-size: 10px; }\n\n.bl-hero__title {\n    font-family: var(--bl-font-heading);\n    font-size: clamp(32px, 5vw, 48px); font-weight: 700;\n    color: var(--bl-white); margin: 0 0 12px;\n    position: relative; z-index: 1;\n}\n.bl-hero__subtitle {\n    font-size: 18px; color: rgba(255,255,255,0.75);\n    max-width: 600px; margin: 0 auto;\n    position: relative; z-index: 1; font-weight: 300;\n}\n\n/* ══════════════════════════════════════\n   FILTRES / CATÉGORIES\n   ══════════════════════════════════════ */\n.bl-filters {\n    background: var(--bl-white);\n    border-bottom: 1px solid var(--bl-border);\n    padding: 0 24px;\n    position: sticky; top: 0; z-index: 50;\n    box-shadow: 0 2px 8px rgba(0,0,0,0.04);\n}\n.bl-filters__inner {\n    max-width: var(--bl-wide); margin: 0 auto;\n    display: flex; align-items: center; justify-content: space-between; gap: 16px;\n    overflow-x: auto; -webkit-overflow-scrolling: touch;\n}\n.bl-filters__categories {\n    display: flex; gap: 0; list-style: none; margin: 0; padding: 0;\n}\n.bl-filters__cat {\n    padding: 16px 20px; font-size: 14px; font-weight: 600;\n    color: var(--bl-text-light); text-decoration: none;\n    border-bottom: 3px solid transparent;\n    transition: var(--bl-transition); white-space: nowrap; cursor: pointer;\n}\n.bl-filters__cat:hover { color: var(--bl-primary); background: rgba(26,58,92,0.03); }\n.bl-filters__cat.active { color: var(--bl-accent); border-bottom-color: var(--bl-accent); }\n.bl-filters__count {\n    font-size: 11px; background: var(--bl-bg); color: var(--bl-text-light);\n    padding: 2px 8px; border-radius: 10px; margin-left: 6px; font-weight: 500;\n}\n\n.bl-filters__search { position: relative; min-width: 220px; }\n.bl-filters__search input {\n    width: 100%; padding: 8px 16px 8px 38px;\n    border: 1px solid var(--bl-border); border-radius: 20px;\n    font-size: 13px; font-family: var(--bl-font-body);\n    background: var(--bl-bg); transition: var(--bl-transition); outline: none;\n}\n.bl-filters__search input:focus {\n    border-color: var(--bl-accent); background: var(--bl-white);\n    box-shadow: 0 0 0 3px rgba(200,149,108,0.15);\n}\n.bl-filters__search-icon {\n    position: absolute; left: 14px; top: 50%; transform: translateY(-50%);\n    color: var(--bl-text-light); width: 16px; height: 16px; pointer-events: none;\n}\n\n/* ══════════════════════════════════════\n   GRILLE 3 COLONNES\n   ══════════════════════════════════════ */\n.bl-content {\n    max-width: var(--bl-wide); margin: 0 auto; padding: 40px 24px 60px;\n}\n.bl-grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 28px;\n}\n\n/* ══════════════════════════════════════\n   CARD ARTICLE\n   ══════════════════════════════════════ */\n.bl-card {\n    background: var(--bl-white);\n    border-radius: var(--bl-radius-lg);\n    overflow: hidden;\n    box-shadow: var(--bl-shadow);\n    transition: var(--bl-transition);\n    display: flex; flex-direction: column;\n    border: 1px solid transparent;\n    /* animation scroll */\n    opacity: 0; transform: translateY(24px);\n}\n.bl-card--visible { opacity: 1; transform: translateY(0); }\n.bl-card:hover {\n    transform: translateY(-4px);\n    box-shadow: var(--bl-shadow-hover);\n    border-color: rgba(200,149,108,0.2);\n}\n.bl-card--visible:hover { transform: translateY(-4px); }\n\n/* Image */\n.bl-card__image-link { display: block; text-decoration: none; }\n.bl-card__image {\n    position: relative; width: 100%;\n    aspect-ratio: 16 / 10; overflow: hidden;\n}\n.bl-card__image img {\n    width: 100%; height: 100%; object-fit: cover;\n    transition: transform 0.5s ease;\n}\n.bl-card:hover .bl-card__image img { transform: scale(1.05); }\n\n.bl-card__badge-cat {\n    position: absolute; top: 14px; left: 14px;\n    background: var(--bl-accent); color: var(--bl-white);\n    font-size: 11px; font-weight: 700; text-transform: uppercase;\n    letter-spacing: 0.5px; padding: 4px 12px; border-radius: 20px; z-index: 2;\n}\n.bl-card__time {\n    position: absolute; bottom: 14px; right: 14px;\n    background: rgba(26,58,92,0.85); color: var(--bl-white);\n    font-size: 11px; padding: 4px 10px; border-radius: 12px;\n    backdrop-filter: blur(4px);\n}\n\n/* Body */\n.bl-card__body {\n    padding: 22px 22px 8px; flex: 1;\n    display: flex; flex-direction: column;\n}\n.bl-card__date {\n    font-size: 12px; color: var(--bl-text-light);\n    margin-bottom: 8px; display: flex; align-items: center; gap: 6px;\n}\n.bl-card__date svg { width: 13px; height: 13px; opacity: 0.5; }\n\n.bl-card__title {\n    font-family: var(--bl-font-heading);\n    font-size: 19px; font-weight: 700; color: var(--bl-primary);\n    margin: 0 0 10px; line-height: 1.35;\n    display: -webkit-box; -webkit-line-clamp: 2;\n    -webkit-box-orient: vertical; overflow: hidden;\n}\n.bl-card__title a { color: inherit; text-decoration: none; transition: color 0.2s; }\n.bl-card__title a:hover { color: var(--bl-accent); }\n\n.bl-card__excerpt {\n    font-size: 14px; color: var(--bl-text-light); line-height: 1.6;\n    margin: 0 0 16px; flex: 1;\n    display: -webkit-box; -webkit-line-clamp: 3;\n    -webkit-box-orient: vertical; overflow: hidden;\n}\n\n/* Footer card */\n.bl-card__footer {\n    padding: 0 22px 20px;\n    display: flex; align-items: center; justify-content: space-between;\n}\n.bl-card__author { display: flex; align-items: center; gap: 10px; }\n.bl-card__author-avatar {\n    width: 32px; height: 32px; border-radius: 50%;\n    object-fit: cover; border: 2px solid var(--bl-bg);\n}\n.bl-card__author-name { font-size: 13px; font-weight: 600; color: var(--bl-primary); }\n\n.bl-card__cta {\n    display: inline-flex; align-items: center; gap: 6px;\n    font-size: 13px; font-weight: 600; color: var(--bl-accent);\n    text-decoration: none; padding: 6px 14px; border-radius: 20px;\n    transition: var(--bl-transition); border: 1px solid transparent;\n}\n.bl-card__cta:hover {\n    background: rgba(200,149,108,0.1);\n    border-color: rgba(200,149,108,0.3);\n}\n.bl-card__cta svg { width: 14px; height: 14px; transition: transform 0.2s; }\n.bl-card__cta:hover svg { transform: translateX(3px); }\n\n/* ══════════════════════════════════════\n   ARTICLE À LA UNE (full width)\n   ══════════════════════════════════════ */\n.bl-featured {\n    grid-column: 1 / -1;\n    flex-direction: row !important;\n    border-radius: var(--bl-radius-lg);\n}\n.bl-featured .bl-card__image {\n    aspect-ratio: auto; min-height: 340px;\n    flex: 1.15; min-width: 0;\n}\n.bl-featured .bl-card__wrap {\n    flex: 1; display: flex; flex-direction: column;\n}\n.bl-featured .bl-card__body {\n    padding: 32px 30px 12px; justify-content: center; flex: 1;\n}\n.bl-featured .bl-card__title {\n    font-size: 26px; -webkit-line-clamp: 3;\n}\n.bl-featured .bl-card__excerpt {\n    font-size: 15px; -webkit-line-clamp: 4;\n}\n.bl-featured .bl-card__footer { padding: 0 30px 28px; }\n.bl-featured__label {\n    display: inline-flex; align-items: center; gap: 5px;\n    font-size: 11px; font-weight: 700; text-transform: uppercase;\n    letter-spacing: 1px; color: var(--bl-accent); margin-bottom: 12px;\n}\n.bl-featured__label svg { width: 14px; height: 14px; }\n\n/* ══════════════════════════════════════\n   PAGINATION\n   ══════════════════════════════════════ */\n.bl-pagination {\n    display: flex; align-items: center; justify-content: center;\n    gap: 6px; margin-top: 48px; padding: 0;\n}\n.bl-pagination__btn {\n    display: inline-flex; align-items: center; justify-content: center;\n    min-width: 40px; height: 40px; padding: 0 14px;\n    border: 1px solid var(--bl-border); border-radius: 8px;\n    background: var(--bl-white); color: var(--bl-text);\n    font-size: 14px; font-weight: 500; font-family: var(--bl-font-body);\n    cursor: pointer; transition: var(--bl-transition); text-decoration: none;\n}\n.bl-pagination__btn:hover { border-color: var(--bl-accent); color: var(--bl-accent); }\n.bl-pagination__btn.active {\n    background: var(--bl-accent); border-color: var(--bl-accent);\n    color: var(--bl-white); font-weight: 700;\n}\n.bl-pagination__btn.disabled { opacity: 0.4; cursor: not-allowed; pointer-events: none; }\n.bl-pagination__btn svg { width: 16px; height: 16px; }\n\n/* ══════════════════════════════════════\n   CTA NEWSLETTER\n   ══════════════════════════════════════ */\n.bl-newsletter {\n    background: linear-gradient(135deg, var(--bl-primary) 0%, var(--bl-primary-light) 100%);\n    border-radius: var(--bl-radius-lg); padding: 48px 40px;\n    text-align: center; margin-top: 56px;\n    position: relative; overflow: hidden;\n}\n.bl-newsletter::before {\n    content: \'\'; position: absolute; top: -30%; right: -5%;\n    width: 300px; height: 300px;\n    background: radial-gradient(circle, rgba(200,149,108,0.15) 0%, transparent 70%);\n    border-radius: 50%;\n}\n.bl-newsletter__title {\n    font-family: var(--bl-font-heading);\n    font-size: 28px; font-weight: 700; color: var(--bl-white);\n    margin: 0 0 10px; position: relative; z-index: 1;\n}\n.bl-newsletter__text {\n    font-size: 16px; color: rgba(255,255,255,0.75);\n    margin: 0 0 28px; position: relative; z-index: 1;\n}\n.bl-newsletter__form {\n    display: flex; max-width: 480px; margin: 0 auto;\n    gap: 10px; position: relative; z-index: 1;\n}\n.bl-newsletter__input {\n    flex: 1; padding: 14px 20px;\n    border: 2px solid rgba(255,255,255,0.2); border-radius: 8px;\n    background: rgba(255,255,255,0.1); color: var(--bl-white);\n    font-size: 15px; font-family: var(--bl-font-body); outline: none;\n    transition: var(--bl-transition);\n}\n.bl-newsletter__input::placeholder { color: rgba(255,255,255,0.5); }\n.bl-newsletter__input:focus { border-color: var(--bl-accent); background: rgba(255,255,255,0.15); }\n.bl-newsletter__btn {\n    padding: 14px 28px; background: var(--bl-accent); color: var(--bl-white);\n    border: none; border-radius: 8px; font-size: 15px; font-weight: 700;\n    font-family: var(--bl-font-body); cursor: pointer;\n    transition: var(--bl-transition); white-space: nowrap;\n}\n.bl-newsletter__btn:hover { background: var(--bl-accent-hover); transform: translateY(-1px); }\n.bl-newsletter__rgpd {\n    font-size: 11px; color: rgba(255,255,255,0.45);\n    margin: 14px 0 0; position: relative; z-index: 1;\n}\n\n/* ══════════════════════════════════════\n   RESPONSIVE\n   ══════════════════════════════════════ */\n@media (max-width: 1024px) {\n    .bl-grid { grid-template-columns: repeat(2, 1fr); gap: 22px; }\n    .bl-featured { flex-direction: row !important; }\n    .bl-featured .bl-card__image { min-height: 280px; }\n}\n\n@media (max-width: 768px) {\n    .bl-hero { padding: 40px 20px 36px; }\n    .bl-filters__inner { flex-direction: column; padding: 12px 0; gap: 10px; }\n    .bl-filters__search { width: 100%; min-width: unset; }\n    .bl-featured { flex-direction: column !important; }\n    .bl-featured .bl-card__image { min-height: 220px; flex: none; }\n    .bl-featured .bl-card__title { font-size: 22px; }\n    .bl-newsletter__form { flex-direction: column; }\n}\n\n@media (max-width: 640px) {\n    .bl-grid { grid-template-columns: 1fr; gap: 20px; }\n    .bl-content { padding: 28px 16px 48px; }\n    .bl-card__title { font-size: 17px; }\n    .bl-newsletter { padding: 36px 24px; }\n}', '', 'ia', NULL, NULL, 0, 'Blog', '', 'principal', 'principal', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'frontend', 'public', 'published', 1, 1, '2026-02-08 14:14:21', NULL, '2026-02-09 02:56:33', NULL, 5, 0, 0, 0, 0, 'default', 'page', 'page', 'default', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '', NULL, NULL, NULL, 0, NULL, 'sections', '', '[]', '[]', NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, 1, 1, NULL, '', 'index, follow', 0, 0, NULL, NULL, NULL, NULL);


