--
-- Structure de la table `pages_sections`
--

CREATE TABLE IF NOT EXISTS `pages_sections` (
  `id` int(11) NOT NULL,
  `page_id` int(11) NOT NULL,
  `type` varchar(50) NOT NULL,
  `order` int(11) DEFAULT 0,
  `data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`data`)),
  `created_at` datetime DEFAULT current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Déchargement des données de la table `pages_sections`
--

INSERT INTO `pages_sections` (`id`, `page_id`, `type`, `order`, `data`, `created_at`) VALUES
(1, 2, 'hero', 0, '{\"title\": \"À propos d\'Eduardo De Sul\", \"subtitle\": \"Conseiller immobilier indépendant, spécialiste du marché bordelais, engagé pour une expérience de vente simple, humaine et sécurisée.\", \"image\": null, \"cta_text\": \"Me contacter\", \"cta_link\": \"/contact\"}', '2026-01-23 22:44:46'),
(2, 2, 'presentation', 1, '{\"title\": \"Mon parcours\", \"content\": \"Après plusieurs années dans des environnements exigeants, j\'ai choisi de consacrer ma carrière à l\'accompagnement des propriétaires bordelais. Aujourd\'hui, je suis conseiller immobilier indépendant au sein du réseau eXp France, un modèle moderne qui met l\'humain et l\'expertise locale au centre de la réussite.\"}', '2026-01-23 22:44:46'),
(3, 2, 'presentation', 2, '{\"title\": \"Ma mission\", \"content\": \"Vous aider à vendre votre bien dans les meilleures conditions possibles : le bon prix, le bon acheteur, le bon timing. Mon travail repose sur trois piliers : une analyse rigoureuse des données du marché bordelais, une stratégie pensée sur mesure pour votre bien, et une communication claire, honnête et transparente.\"}', '2026-01-23 22:44:46'),
(4, 2, 'atouts', 3, '{\"title\": \"Mon approche\", \"atout_1_icon\": \"🎯\", \"atout_1_title\": \"Simplicité\", \"atout_1_desc\": \"Je transforme un parcours souvent complexe en un plan clair, lisible et rassurant à chaque étape.\", \"atout_2_icon\": \"🤝\", \"atout_2_title\": \"Proximité\", \"atout_2_desc\": \"Relation humaine, écoute et disponibilité sont au cœur de mon accompagnement.\", \"atout_3_icon\": \"📊\", \"atout_3_title\": \"Expertise locale\", \"atout_3_desc\": \"Chaque quartier de Bordeaux a ses dynamiques. Je m\'appuie sur ces données pour guider vos décisions.\", \"atout_4_icon\": \"\", \"atout_4_title\": \"\", \"atout_4_desc\": \"\", \"atout_5_icon\": \"\", \"atout_5_title\": \"\", \"atout_5_desc\": \"\", \"atout_6_icon\": \"\", \"atout_6_title\": \"\", \"atout_6_desc\": \"\"}', '2026-01-23 22:44:46'),
(5, 2, 'cta', 4, '{\"title\": \"Envie d\'échanger sur votre projet ?\", \"content\": \"Je serais heureux de comprendre votre situation et de vous guider sans engagement.\", \"cta_text\": \"Me contacter\", \"cta_link\": \"/contact\"}', '2026-01-23 22:44:46');


