CREATE TABLE IF NOT EXISTS `pages_seo` (
  `id` int(11) NOT NULL,
  `page_id` int(11) NOT NULL,
  `seo_score` int(11) DEFAULT 0 COMMENT 'Score SEO de 0 à 100',
  `serp_position` int(11) DEFAULT NULL COMMENT 'Position dans les résultats Google',
  `serp_keyword` varchar(255) DEFAULT NULL COMMENT 'Mot-clé suivi pour SERP',
  `is_indexed` tinyint(1) DEFAULT NULL COMMENT '1=indexé, 0=non indexé, NULL=inconnu',
  `last_check` datetime DEFAULT NULL COMMENT 'Dernière vérification',
  `indexing_requested` datetime DEFAULT NULL COMMENT 'Date demande indexation GSC',
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ------------------------------------------------------------
-- Table : page_sections
-- ------------------------------------------------------------

-- --------------------------------------------------------

--
-- Structure de la table `page_sections`
--

CREATE TABLE IF NOT EXISTS `page_sections` (
  `id` int(11) NOT NULL,
  `page_id` int(11) NOT NULL,
  `section_type` varchar(100) NOT NULL,
  `name` varchar(255) DEFAULT NULL,
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`content`)),
  `styles` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`styles`)),
  `settings` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL CHECK (json_valid(`settings`)),
  `position` int(11) NOT NULL DEFAULT 0,
  `is_visible` tinyint(1) DEFAULT 1,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ------------------------------------------------------------
-- Table : page_templates
-- ------------------------------------------------------------

-- --------------------------------------------------------

--
-- Structure de la table `page_templates`
--

CREATE TABLE IF NOT EXISTS `page_templates` (
  `id` int(11) NOT NULL,
  `name` varchar(255) NOT NULL,
  `description` text DEFAULT NULL,
  `thumbnail` varchar(500) DEFAULT NULL,
  `category` varchar(100) DEFAULT 'general',
  `sections_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL CHECK (json_valid(`sections_data`)),
  `is_premium` tinyint(1) DEFAULT 0,
  `sort_order` int(11) DEFAULT 0,
